const QColor IconCyan( 34, 211, 238 );
const QColor IconMuted( 148, 163, 184 );

qreal iconDevicePixelRatio()
{
	if( const auto* screen = QGuiApplication::primaryScreen() )
	{
		return std::max( 1.0, screen->devicePixelRatio() );
	}

	return 1.0;
}

QPen iconPen( const QColor& color, int size, qreal widthFactor = 0.09 )
{
	const auto width = std::max( 1.25, size * widthFactor );
	return { color, width, Qt::SolidLine, Qt::RoundCap, Qt::RoundJoin };
}

QLabel* createIconLabel( const QPixmap& pixmap, int logicalSize, QWidget* parent )
{
	auto* label = new QLabel( parent );
	label->setPixmap( pixmap );
	label->setFixedSize( logicalSize, logicalSize );
	label->setAlignment( Qt::AlignCenter );
	label->setScaledContents( false );
	label->setStyleSheet( QStringLiteral( "background: transparent;" ) );
	return label;
}

void applyButtonIcon( QPushButton* button, const QPixmap& icon )
{
	if( button == nullptr || icon.isNull() )
	{
		return;
	}

	button->setIcon( QIcon( icon ) );
	button->setIconSize( QSize( 16, 16 ) );
}

void drawUserGlyph( QPainter& painter, int size, const QColor& color )
{
	painter.setPen( Qt::NoPen );
	painter.setBrush( color );
	const auto cx = size * 0.5;
	painter.drawEllipse( QRectF( cx - size * 0.15, size * 0.14, size * 0.30, size * 0.30 ) );
	painter.drawRoundedRect( QRectF( cx - size * 0.24, size * 0.46, size * 0.48, size * 0.34 ), size * 0.12, size * 0.12 );
}

void drawKeyGlyph( QPainter& painter, int size, const QColor& color )
{
	painter.setPen( iconPen( color, size ) );
	painter.setBrush( QColor( color.red(), color.green(), color.blue(), 48 ) );
	painter.drawArc( QRectF( size * 0.30, size * 0.12, size * 0.40, size * 0.40 ), 0, 180 * 16 );
	painter.drawRoundedRect( QRectF( size * 0.26, size * 0.44, size * 0.48, size * 0.40 ), size * 0.08, size * 0.08 );
	painter.setBrush( color );
	painter.setPen( Qt::NoPen );
	painter.drawEllipse( QRectF( size * 0.44, size * 0.56, size * 0.12, size * 0.12 ) );
}

void drawNetworkGlyph( QPainter& painter, int size, const QColor& color )
{
	painter.setPen( iconPen( color, size, 0.085 ) );
	painter.setBrush( Qt::NoBrush );
	painter.drawEllipse( QRectF( size * 0.12, size * 0.12, size * 0.76, size * 0.76 ) );
	painter.drawLine( QPointF( size * 0.5, size * 0.20 ), QPointF( size * 0.5, size * 0.80 ) );
	painter.drawLine( QPointF( size * 0.20, size * 0.5 ), QPointF( size * 0.80, size * 0.5 ) );
	painter.setBrush( color );
	painter.setPen( Qt::NoPen );
	painter.drawEllipse( QRectF( size * 0.43, size * 0.43, size * 0.14, size * 0.14 ) );
}

void drawMonitorGlyph( QPainter& painter, int size, const QColor& color )
{
	painter.setPen( iconPen( color, size ) );
	painter.setBrush( QColor( color.red(), color.green(), color.blue(), 36 ) );
	painter.drawRoundedRect( QRectF( size * 0.12, size * 0.16, size * 0.76, size * 0.52 ), size * 0.08, size * 0.08 );
	painter.setBrush( Qt::NoBrush );
	painter.drawLine( QPointF( size * 0.5, size * 0.68 ), QPointF( size * 0.5, size * 0.76 ) );
	painter.drawLine( QPointF( size * 0.34, size * 0.76 ), QPointF( size * 0.66, size * 0.76 ) );
}

void drawLogonHeaderGlyph( QPainter& painter, int size, const QColor& color )
{
	drawUserGlyph( painter, size, color );
}

void drawRemoteHeaderGlyph( QPainter& painter, int size, const QColor& color )
{
	const auto pen = iconPen( color, size, 0.10 );
	painter.setPen( pen );
	painter.setBrush( QColor( color.red(), color.green(), color.blue(), 28 ) );

	const QRectF screen( size * 0.11, size * 0.15, size * 0.78, size * 0.48 );
	painter.drawRoundedRect( screen, size * 0.07, size * 0.07 );

	painter.setBrush( Qt::NoBrush );
	painter.drawLine( QPointF( size * 0.50, size * 0.63 ), QPointF( size * 0.50, size * 0.71 ) );
	painter.drawLine( QPointF( size * 0.35, size * 0.71 ), QPointF( size * 0.65, size * 0.71 ) );

	painter.setBrush( color );
	painter.setPen( Qt::NoPen );
	painter.drawEllipse( QRectF( size * 0.56, size * 0.27, size * 0.10, size * 0.10 ) );

	painter.setPen( QPen( color, pen.widthF(), Qt::SolidLine, Qt::RoundCap, Qt::RoundJoin ) );
	painter.drawLine( QPointF( size * 0.61, size * 0.32 ), QPointF( size * 0.72, size * 0.43 ) );
	painter.drawLine( QPointF( size * 0.72, size * 0.43 ), QPointF( size * 0.66, size * 0.43 ) );
	painter.drawLine( QPointF( size * 0.72, size * 0.43 ), QPointF( size * 0.72, size * 0.37 ) );
}

QLabel* createCimedTitleLabel( QWidget* parent )
{
	constexpr int labelWidth = 164;
	constexpr int labelHeight = 34;
	const auto dpr = iconDevicePixelRatio();

	QPixmap pixmap( static_cast<int>( std::lround( labelWidth * dpr ) ),
					static_cast<int>( std::lround( labelHeight * dpr ) ) );
	pixmap.fill( Qt::transparent );
	pixmap.setDevicePixelRatio( dpr );

	QPainter painter( &pixmap );
	painter.setRenderHint( QPainter::Antialiasing, true );
	painter.setRenderHint( QPainter::TextAntialiasing, true );

	QFont font = parent->font();
	font.setPixelSize( 21 );
	font.setBold( true );
	font.setLetterSpacing( QFont::AbsoluteSpacing, 2.5 );

	const QString title = QStringLiteral( "CIMED" );
	const QFontMetrics metrics( font );
	const auto textWidth = metrics.horizontalAdvance( title );
	const auto x = ( labelWidth - textWidth ) / 2.0;
	const auto y = ( labelHeight + metrics.ascent() - metrics.descent() ) / 2.0;

	QPainterPath textPath;
	textPath.addText( x, y, font, title );

	painter.setPen( Qt::NoPen );
	painter.setBrush( QColor( 0, 0, 0, 90 ) );
	painter.drawPath( textPath.translated( 1.2, 2.0 ) );

	QLinearGradient metal( 0, y - metrics.ascent(), 0, y + metrics.descent() );
	metal.setColorAt( 0.0, QColor( 255, 236, 179 ) );
	metal.setColorAt( 0.30, QColor( 218, 175, 78 ) );
	metal.setColorAt( 0.55, QColor( 196, 148, 52 ) );
	metal.setColorAt( 1.0, QColor( 142, 98, 28 ) );

	painter.setBrush( metal );
	painter.setPen( QPen( QColor( 255, 248, 220, 150 ), 0.9 ) );
	painter.drawPath( textPath );

	auto* label = new QLabel( parent );
	label->setPixmap( pixmap );
	label->setAlignment( Qt::AlignHCenter );
	label->setStyleSheet( QStringLiteral( "background: transparent;" ) );
	return label;
}

QLabel* createInstituteTextLabel( QWidget* parent )
{
	constexpr int labelWidth = 164;
	constexpr int labelHeight = 40;
	const auto dpr = iconDevicePixelRatio();

	QPixmap pixmap( static_cast<int>( std::lround( labelWidth * dpr ) ),
					static_cast<int>( std::lround( labelHeight * dpr ) ) );
	pixmap.fill( Qt::transparent );
	pixmap.setDevicePixelRatio( dpr );

	QPainter painter( &pixmap );
	painter.setRenderHint( QPainter::Antialiasing, true );
	painter.setRenderHint( QPainter::TextAntialiasing, true );

	const auto drawCenteredLine = [&]( const QString& text, int pixelSize, bool bold, qreal baselineY ) {
		QFont font = parent->font();
		font.setPixelSize( pixelSize );
		font.setBold( bold );

		const QFontMetrics metrics( font );
		const auto x = ( labelWidth - metrics.horizontalAdvance( text ) ) / 2.0;

		QPainterPath path;
		path.addText( x, baselineY, font, text );

		painter.setPen( Qt::NoPen );
		painter.setBrush( QColor( 0, 0, 0, 85 ) );
		painter.drawPath( path.translated( 0.8, 1.2 ) );
		painter.setBrush( QColor( 248, 250, 252 ) );
		painter.drawPath( path );
	};

	drawCenteredLine( QStringLiteral( "Centro de InformГЎtica" ), 10, true, 14.0 );
	drawCenteredLine( QStringLiteral( "do HCFMB" ), 9, false, 30.0 );

	auto* label = new QLabel( parent );
	label->setPixmap( pixmap );
	label->setAlignment( Qt::AlignHCenter );
	label->setStyleSheet( QStringLiteral( "background: transparent;" ) );
	return label;
}

QPixmap coloredIconPixmap( const std::function<void(QPainter&, int, const QColor&)>& drawFn, int size, const QColor& color )
{
	const auto dpr = iconDevicePixelRatio();
	QPixmap pixmap( static_cast<int>( std::lround( size * dpr ) ),
					static_cast<int>( std::lround( size * dpr ) ) );
	pixmap.fill( Qt::transparent );
	pixmap.setDevicePixelRatio( dpr );

	QPainter painter( &pixmap );
	painter.setRenderHint( QPainter::Antialiasing, true );
	painter.setRenderHint( QPainter::SmoothPixmapTransform, true );
	drawFn( painter, size, color );
	return pixmap;
}

QPixmap logoPixmapForBrandPanel( int maxWidth )
{
	QImage image( QStringLiteral( ":/core/cimed-logo.png" ) );
	if( image.isNull() )
	{
		return {};
	}

	image = image.convertToFormat( QImage::Format_ARGB32 );
	for( int y = 0; y < image.height(); ++y )
	{
		for( int x = 0; x < image.width(); ++x )
		{
			QColor color = image.pixelColor( x, y );
			if( color.red() > 242 && color.green() > 242 && color.blue() > 242 )
			{
				color.setAlpha( 0 );
				image.setPixelColor( x, y, color );
			}
		}
	}

	const int w = image.width();
	const int h = image.height();
	const int emptyThreshold = std::max( 1, w / 100 );
	const int minGapRows = 6;
	const int scanStart = static_cast<int>( h * 0.35 );
	int cropHeight = h;

	const auto rowDensity = [&]( int y ) {
		int count = 0;
		for( int x = 0; x < w; ++x )
		{
			if( image.pixelColor( x, y ).alpha() > 10 )
			{
				++count;
			}
		}
		return count;
	};

	for( int y = scanStart; y < h; )
	{
		if( rowDensity( y ) < emptyThreshold )
		{
			const int gapStart = y;
			while( y < h && rowDensity( y ) < emptyThreshold )
			{
				++y;
			}

			if( y - gapStart >= minGapRows )
			{
				cropHeight = gapStart;
				break;
			}
		}
		else
		{
			++y;
		}
	}

	image = image.copy( 0, 0, w, cropHeight );
	QPixmap pixmap = QPixmap::fromImage( image );
	if( maxWidth > 0 && pixmap.width() > maxWidth )
	{
		return pixmap.scaledToWidth( maxWidth, Qt::SmoothTransformation );
	}

	return pixmap;
}

