QPixmap CimedDialogStyle::drawHeaderIcon( HeaderIcon icon, int size )
{
	switch( icon )
	{
	case HeaderIcon::Logon:
		return coloredIconPixmap( drawLogonHeaderGlyph, size, IconCyan );
	case HeaderIcon::RemoteAccess:
		return coloredIconPixmap( drawRemoteHeaderGlyph, size, IconCyan );
	default:
		return {};
	}
}

QPixmap CimedDialogStyle::drawInputIcon( InputIcon icon, int size )
{
	switch( icon )
	{
	case InputIcon::User:
		return coloredIconPixmap( drawUserGlyph, size, IconMuted );
	case InputIcon::Password:
		return coloredIconPixmap( drawKeyGlyph, size, IconMuted );
	case InputIcon::Network:
		return coloredIconPixmap( drawNetworkGlyph, size, IconMuted );
	default:
		return {};
	}
}

QPixmap CimedDialogStyle::drawDesktopAccessHeroIcon( int size )
{
	const auto dpr = iconDevicePixelRatio();
	QPixmap pixmap( static_cast<int>( std::lround( size * dpr ) ),
					static_cast<int>( std::lround( size * dpr ) ) );
	pixmap.fill( Qt::transparent );
	pixmap.setDevicePixelRatio( dpr );

	QPainter painter( &pixmap );
	painter.setRenderHint( QPainter::Antialiasing, true );
	painter.setRenderHint( QPainter::SmoothPixmapTransform, true );

	for( const auto radiusFactor : { 0.55, 0.42 } )
	{
		QRadialGradient glow( size * 0.5, size * 0.5, size * radiusFactor );
		glow.setColorAt( 0.0, QColor( 34, 211, 238, 70 ) );
		glow.setColorAt( 1.0, QColor( 34, 211, 238, 0 ) );
		painter.setPen( Qt::NoPen );
		painter.setBrush( glow );
		painter.drawEllipse( QRectF( size * ( 0.5 - radiusFactor ), size * ( 0.5 - radiusFactor ),
									 size * radiusFactor * 2.0, size * radiusFactor * 2.0 ) );
	}

	drawMonitorGlyph( painter, size, IconCyan );
	painter.setPen( iconPen( IconCyan, size ) );
	painter.setBrush( Qt::NoBrush );
	painter.drawEllipse( QRectF( size * 0.30, size * 0.28, size * 0.40, size * 0.22 ) );
	painter.setBrush( IconCyan );
	painter.setPen( Qt::NoPen );
	painter.drawEllipse( QRectF( size * 0.44, size * 0.34, size * 0.12, size * 0.12 ) );

	return pixmap;
}

QPixmap CimedDialogStyle::logoWithTransparentBackground( const QString& resourcePath, int maxWidth )
{
	QImage image( resourcePath );
	if( image.isNull() )
	{
		return {};
	}

	image = image.convertToFormat( QImage::Format_ARGB32 );
	for( int y = 0; y < image.height(); ++y )
	{
		for( int x = 0; x < image.width(); ++x )
		{
			QColor color = image.pixelColor( x, y );
			if( color.red() > 242 && color.green() > 242 && color.blue() > 242 )
			{
				color.setAlpha( 0 );
				image.setPixelColor( x, y, color );
			}
		}
	}

	QPixmap pixmap = QPixmap::fromImage( image );
	if( maxWidth > 0 && pixmap.width() > maxWidth )
	{
		return pixmap.scaledToWidth( maxWidth, Qt::SmoothTransformation );
	}

	return pixmap;
}

QPixmap CimedDialogStyle::drawButtonIcon( const QString& kind, int size )
{
	const auto dpr = iconDevicePixelRatio();
	QPixmap pixmap( static_cast<int>( std::lround( size * dpr ) ),
					static_cast<int>( std::lround( size * dpr ) ) );
	pixmap.fill( Qt::transparent );
	pixmap.setDevicePixelRatio( dpr );

	QPainter painter( &pixmap );
	painter.setRenderHint( QPainter::Antialiasing, true );
	painter.setRenderHint( QPainter::SmoothPixmapTransform, true );

	const QColor light( 248, 250, 252 );
	painter.setPen( iconPen( light, size, 0.10 ) );

	if( kind == QStringLiteral( "check" ) )
	{
		painter.drawLine( QPointF( size * 0.18, size * 0.52 ), QPointF( size * 0.42, size * 0.76 ) );
		painter.drawLine( QPointF( size * 0.42, size * 0.76 ), QPointF( size * 0.84, size * 0.24 ) );
	}
	else if( kind == QStringLiteral( "star" ) )
	{
		QPolygonF star;
		for( int i = 0; i < 5; ++i )
		{
			const auto angle = ( i * 72 - 90 ) * M_PI / 180.0;
			star << QPointF( size * 0.5 + std::cos( angle ) * size * 0.34,
							 size * 0.5 + std::sin( angle ) * size * 0.34 );
			const auto inner = angle + ( 36 * M_PI / 180.0 );
			star << QPointF( size * 0.5 + std::cos( inner ) * size * 0.16,
							 size * 0.5 + std::sin( inner ) * size * 0.16 );
		}
		painter.setBrush( light );
		painter.drawPolygon( star );
	}
	else if( kind == QStringLiteral( "shield" ) )
	{
		QPainterPath shield;
		shield.moveTo( size * 0.5, size * 0.12 );
		shield.lineTo( size * 0.82, size * 0.24 );
		shield.lineTo( size * 0.76, size * 0.66 );
		shield.quadTo( size * 0.5, size * 0.9, size * 0.24, size * 0.66 );
		shield.lineTo( size * 0.18, size * 0.24 );
		shield.closeSubpath();
		painter.setBrush( QColor( light.red(), light.green(), light.blue(), 60 ) );
		painter.drawPath( shield );
		painter.drawLine( QPointF( size * 0.34, size * 0.52 ), QPointF( size * 0.48, size * 0.66 ) );
		painter.drawLine( QPointF( size * 0.48, size * 0.66 ), QPointF( size * 0.7, size * 0.36 ) );
	}
	else if( kind == QStringLiteral( "connect" ) )
	{
		painter.drawLine( QPointF( size * 0.2, size * 0.5 ), QPointF( size * 0.46, size * 0.5 ) );
		painter.drawLine( QPointF( size * 0.54, size * 0.5 ), QPointF( size * 0.8, size * 0.5 ) );
		painter.drawEllipse( QRectF( size * 0.42, size * 0.38, size * 0.16, size * 0.24 ) );
	}
	else if( kind == QStringLiteral( "deny" ) )
	{
		painter.drawEllipse( QRectF( size * 0.2, size * 0.2, size * 0.6, size * 0.6 ) );
		painter.drawLine( QPointF( size * 0.3, size * 0.3 ), QPointF( size * 0.7, size * 0.7 ) );
	}
	else if( kind == QStringLiteral( "clock" ) )
	{
		painter.drawEllipse( QRectF( size * 0.14, size * 0.14, size * 0.72, size * 0.72 ) );
		painter.drawLine( QPointF( size * 0.5, size * 0.5 ), QPointF( size * 0.5, size * 0.28 ) );
		painter.drawLine( QPointF( size * 0.5, size * 0.5 ), QPointF( size * 0.66, size * 0.5 ) );
	}

	return pixmap;
}

void CimedDialogStyle::centerDialogOnScreen( QDialog* dialog, int width, int height )
{
	const auto* screen = QGuiApplication::primaryScreen();
	if( screen == nullptr )
	{
		return;
	}

	const auto available = screen->availableGeometry();
	dialog->move( available.x() + ( available.width() - width ) / 2,
				  available.y() + ( available.height() - height ) / 2 );
}

QWidget* CimedDialogStyle::createHeader( QWidget* parent, const QString& title, HeaderIcon icon )
{
	auto* headerWidget = new QWidget( parent );
	headerWidget->setStyleSheet( headerStyleSheet() );
	auto* headerLayout = new QHBoxLayout( headerWidget );
	headerLayout->setContentsMargins( 16, 12, 16, 12 );
	headerLayout->setSpacing( 10 );

	if( icon != HeaderIcon::None )
	{
		constexpr int headerIconSize = 22;
		headerLayout->addWidget( createIconLabel( drawHeaderIcon( icon, headerIconSize ), headerIconSize, headerWidget ) );
	}

	auto* headerTitle = new QLabel( title, headerWidget );
	headerTitle->setStyleSheet( headerTitleStyleSheet() );
	headerLayout->addWidget( headerTitle );
	headerLayout->addStretch();

	return headerWidget;
}

