	headerLayout->setSpacing( 10 );

	if( icon != HeaderIcon::None )
	{
		constexpr int headerIconSize = 22;
		headerLayout->addWidget( createIconLabel( drawHeaderIcon( icon, headerIconSize ), headerIconSize, headerWidget ) );
	}

	auto* headerTitle = new QLabel( title, headerWidget );
	headerTitle->setStyleSheet( headerTitleStyleSheet() );
	headerLayout->addWidget( headerTitle );
	headerLayout->addStretch();

	return headerWidget;
}

