void CimedDialogStyle::buildDialogShell( QDialog* dialog,
										 const QString& windowTitle,
										 int width,
										 int height,
										 HeaderIcon headerIcon,
										 QWidget*& headerWidget,
										 QWidget*& brandPanel,
										 QWidget*& contentPanel,
										 QVBoxLayout*& contentLayout,
										 QWidget*& footerWidget,
										 bool includeBrandPanel )
{
	dialog->setWindowTitle( windowTitle );
	dialog->setWindowFlags( dialog->windowFlags() | Qt::WindowStaysOnTopHint );
	dialog->setModal( true );
	dialog->setFixedSize( width, height );
	dialog->setStyleSheet( dialogStyleSheet() );
	centerDialogOnScreen( dialog, width, height );

	auto* rootLayout = new QVBoxLayout( dialog );
	rootLayout->setContentsMargins( 0, 0, 0, 0 );
	rootLayout->setSpacing( 0 );

	headerWidget = createHeader( dialog, windowTitle, headerIcon );
	rootLayout->addWidget( headerWidget );

	auto* bodyWidget = new QWidget( dialog );
	bodyWidget->setStyleSheet( QStringLiteral( "background: transparent;" ) );
	auto* bodyLayout = new QHBoxLayout( bodyWidget );
	bodyLayout->setContentsMargins( 24, 24, 24, 16 );
	bodyLayout->setSpacing( 24 );

	brandPanel = nullptr;
	if( includeBrandPanel )
	{
		brandPanel = createBrandPanel( bodyWidget );
		bodyLayout->addWidget( brandPanel );
		bodyLayout->addWidget( createVerticalSeparator( bodyWidget ) );
	}

	contentPanel = new QWidget( bodyWidget );
	contentPanel->setObjectName( QStringLiteral( "cimedContentPanel" ) );
	contentPanel->setStyleSheet( contentPanelStyleSheet() );
	contentLayout = new QVBoxLayout( contentPanel );
	contentLayout->setContentsMargins( 14, 14, 14, 14 );
	contentLayout->setSpacing( 10 );

	bodyLayout->addWidget( contentPanel, 1 );
	rootLayout->addWidget( bodyWidget, 1 );

	footerWidget = createFooter( dialog );
	rootLayout->addWidget( footerWidget );
}

iconDevicePixelRatio()
{
	if( const auto* screen = QGuiApplication::primaryScreen() )
	{
		return std::max( 1.0, screen->devicePixelRatio() );
	}

	return 1.0;
}

