QPixmap drawEyeIcon( int size, const QColor& color )
{
	const auto* screen = QGuiApplication::primaryScreen();
	const auto dpr = screen ? std::max( 1.0, screen->devicePixelRatio() ) : 1.0;
	QPixmap pixmap( static_cast<int>( std::lround( size * dpr ) ),
					static_cast<int>( std::lround( size * dpr ) ) );
	pixmap.fill( Qt::transparent );
	pixmap.setDevicePixelRatio( dpr );

	QPainter painter( &pixmap );
	painter.setRenderHint( QPainter::Antialiasing, true );
	const auto penWidth = std::max( 1.25, size * 0.09 );
	painter.setPen( QPen( color, penWidth, Qt::SolidLine, Qt::RoundCap, Qt::RoundJoin ) );
	painter.setBrush( Qt::NoBrush );
	painter.drawEllipse( QRectF( size * 0.12, size * 0.28, size * 0.76, size * 0.44 ) );
	painter.setBrush( color );
	painter.setPen( Qt::NoPen );
	painter.drawEllipse( QRectF( size * 0.38, size * 0.40, size * 0.24, size * 0.24 ) );

	return pixmap;
}

}

