PasswordDialog::~PasswordDialog() = default;



QString PasswordDialog::username() const
{
	return m_usernameEdit->text();
}



CryptoCore::PlaintextPassword PasswordDialog::password() const
{
	return m_passwordEdit->text().toUtf8();
}



AuthenticationCredentials PasswordDialog::credentials() const
{
	AuthenticationCredentials cred;
	cred.setLogonUsername( username() );
	cred.setLogonPassword( password() );

	return cred;
}



void PasswordDialog::attemptAuthentication()
{
	if( VeyonCore::platform().userFunctions().authenticate( username(), password() ) == false )
	{
		SystemTrayIcon::notifyLocalSessionTray( SystemTrayIcon::StatusIndicator::Error,
												QStringLiteral( "Estado: Senha incorreta" ) );
		showPasswordError();
		return;
	}

	QDialog::accept();
}



void PasswordDialog::showPasswordError()
{
	m_errorLabel->setVisible( true );
	m_contentPanel->setStyleSheet( errorPanelStyleSheet() );
	m_usernameFrame->setStyleSheet( errorInputFrameStyleSheet() );
	m_passwordFrame->setStyleSheet( errorInputFrameStyleSheet() );
	{
		const QSignalBlocker blocker( m_passwordEdit );
		m_passwordEdit->clear();
	}
	m_passwordEdit->setFocus();
}



void PasswordDialog::clearPasswordError()
{
	if( m_errorLabel->isVisible() == false )
	{
		return;
	}

	m_errorLabel->setVisible( false );
	m_contentPanel->setStyleSheet( CimedDialogStyle::contentPanelStyleSheet() );
	m_usernameFrame->setStyleSheet( CimedDialogStyle::inputFrameStyleSheet() );
	m_passwordFrame->setStyleSheet( CimedDialogStyle::inputFrameStyleSheet() );
}



void PasswordDialog::updateAuthenticateButton()
{
	m_authenticateButton->setEnabled( username().isEmpty() == false && password().isEmpty() == false );
}

