QString ComputerSupportInfo::productLabel()
{
	return QStringLiteral( "Veyon CIMED" );
}

QString ComputerSupportInfo::productVersion()
{
	return QStringLiteral( "VERSГғO 1.0" );
}

QString ComputerSupportInfo::hostname()
{
	const auto name = QHostInfo::localHostName();
	return name.isEmpty() ? QStringLiteral( "desconhecido" ) : name;
}

QString ComputerSupportInfo::localIpAddress()
{
	for( const auto& address : QNetworkInterface::allAddresses() )
	{
		if( address.protocol() == QAbstractSocket::IPv4Protocol && address.isLoopback() == false )
		{
			return address.toString();
		}
	}

	return QStringLiteral( "desconhecido" );
}

QString ComputerSupportInfo::adUserName()
{
	const auto user = qEnvironmentVariable( "USERNAME" );
	const auto dnsDomain = qEnvironmentVariable( "USERDNSDOMAIN" );
	if( dnsDomain.isEmpty() == false && user.isEmpty() == false )
	{
		return dnsDomain + QLatin1Char( '\\' ) + user;
	}

	const auto domain = qEnvironmentVariable( "USERDOMAIN" );
	if( domain.isEmpty() == false &&
		domain.compare( QStringLiteral( "WORKGROUP" ), Qt::CaseInsensitive ) != 0 &&
		user.isEmpty() == false )
	{
		return domain + QLatin1Char( '\\' ) + user;
	}

	return user.isEmpty() ? QStringLiteral( "desconhecido" ) : user;
}

QString ComputerSupportInfo::operatingSystem()
{
	const auto prettyName = QSysInfo::prettyProductName();
	return prettyName.isEmpty() ? QStringLiteral( "desconhecido" ) : prettyName;
}

