QString integrityStateFilePath()
{
	return QDir( QCoreApplication::applicationDirPath() ).filePath( QStringLiteral( "acessos_integrity_state.txt" ) );
}

QHash<QString, QString> loadIntegrityState()
{
	QHash<QString, QString> state;

	QFile file( integrityStateFilePath() );
	if( file.open( QIODevice::ReadOnly | QIODevice::Text ) == false )
	{
		return state;
	}

	QTextStream in( &file );
	in.setEncoding( QStringConverter::System );

	while( in.atEnd() == false )
	{
		const auto line = in.readLine().trimmed();
		const auto separatorIndex = line.indexOf( QLatin1Char( '=' ) );
		if( separatorIndex <= 0 )
		{
			continue;
		}

		state.insert( line.left( separatorIndex ), line.mid( separatorIndex + 1 ) );
	}

	return state;
}

QString normalizeLogContent( const QString& content )
{
	auto normalized = content;

	if( normalized.startsWith( QChar( 0xFEFF ) ) )
	{
		normalized.remove( 0, 1 );
	}

	normalized.replace( QStringLiteral( "\r\n" ), QStringLiteral( "\n" ) );
	normalized.replace( QLatin1Char( '\r' ), QLatin1Char( '\n' ) );

	return normalized;
}

QString decodeLogFileBytes( const QByteArray& data )
{
	auto payload = data;

	if( payload.startsWith( "\xEF\xBB\xBF" ) )
	{
		payload = payload.mid( 3 );
	}

	QStringDecoder utf8Decoder( QStringConverter::Utf8 );
	const auto utf8Content = utf8Decoder( payload );
	if( utf8Decoder.hasError() == false )
	{
		return normalizeLogContent( utf8Content );
	}

	QStringDecoder systemDecoder( QStringConverter::System );
	return normalizeLogContent( systemDecoder( payload ) );
}

void configureLogTextStream( QTextStream& stream )
{
	stream.setEncoding( QStringConverter::Utf8 );
}

void ensureParentDirectoryExists( const QString& filePath )
{
	const auto directoryPath = QFileInfo( filePath ).absolutePath();
	if( directoryPath.isEmpty() )
	{
		return;
	}

	QDir().mkpath( directoryPath );
}

struct AccessLogIntegrityResult
{
	QStringList invalidLineNumbers;
	QStringList tamperSignatures;

	bool hasIssues() const
	{
		return invalidLineNumbers.isEmpty() == false;
	}

	QString fingerprint() const
	{
		return AccessLogWriter::sha256Hex( tamperSignatures.join( QLatin1Char( '|' ) ) );
	}
};

AccessLogIntegrityResult analyzeAccessLogIntegrity( const QString& fileContent )
{
	AccessLogIntegrityResult result;
	const auto lines = fileContent.split( QLatin1Char( '\n' ), Qt::KeepEmptyParts );
	const auto hashMarker = QStringLiteral( " | SHA256: " );

	auto lineNumber = 0;

	for( const auto& rawLine : lines )
	{
		const auto line = rawLine.trimmed();
		++lineNumber;

		if( line.isEmpty() )
		{
			continue;
		}

		const auto markerIndex = line.lastIndexOf( hashMarker );
		if( markerIndex < 0 )
		{
			result.invalidLineNumbers.append( QString::number( lineNumber ) );
			result.tamperSignatures.append( QStringLiteral( "%1:missing-hash" ).arg( lineNumber ) );
			continue;
		}

		const auto messagePart = line.left( markerIndex );
		const auto storedHash = line.mid( markerIndex + hashMarker.size() ).trimmed();
		const auto expectedHash = AccessLogWriter::sha256Hex( messagePart );

		if( storedHash.compare( expectedHash, Qt::CaseInsensitive ) != 0 )
		{
			result.invalidLineNumbers.append( QString::number( lineNumber ) );
			result.tamperSignatures.append( QStringLiteral( "%1:%2" ).arg( lineNumber ).arg( storedHash ) );
		}
	}

	return result;
}

void saveIntegrityState( const QHash<QString, QString>& state )
{
	QFile file( integrityStateFilePath() );
	if( file.open( QIODevice::WriteOnly | QIODevice::Text | QIODevice::Truncate ) == false )
	{
		vWarning() << "[access-log-integrity] failed to write integrity state";
		return;
	}

	QTextStream out( &file );
	out.setEncoding( QStringConverter::System );

	for( auto it = state.constBegin(); it != state.constEnd(); ++it )
	{
		out << it.key() << QLatin1Char( '=' ) << it.value() << Qt::endl;
	}
}

void updateIntegrityStateAfterSync()
{
	QString syncedContent;
	if( AccessLogWriter::tryReadLogFileContent( AccessLogWriter::networkAccessLogPath(), syncedContent ) == false )
	{
		return;
	}

	const auto integrityResult = analyzeAccessLogIntegrity( syncedContent );
	auto state = loadIntegrityState();

	if( integrityResult.hasIssues() )
	{
		const auto fingerprint = integrityResult.fingerprint();
		state.insert( QStringLiteral( "rede" ), fingerprint );
	}
	else
	{
		state.remove( QStringLiteral( "rede" ) );
	}

	saveIntegrityState( state );
}

class AccessLogValidationScheduler : public QObject
{
public:
	explicit AccessLogValidationScheduler( QObject* parent ) :
		QObject( parent )
	{
		m_timer.setSingleShot( true );
		connect( &m_timer, &QTimer::timeout, this, [this]() {
			vInfo() << "[access-log-integrity] running scheduled daily validation";
			AccessLogWriter::validateAccessLogsOnStartup();
			scheduleNextRun();
		} );
		scheduleNextRun();
	}

private:
	void scheduleNextRun()
	{
		const auto now = QDateTime::currentDateTime();
		auto nextRun = QDateTime( now.date(), QTime( 15, 0, 0 ) );
		if( nextRun <= now )
		{
			nextRun = nextRun.addDays( 1 );
		}

		m_timer.start( static_cast<int>( now.msecsTo( nextRun ) ) );
		vInfo() << "[access-log-integrity] next scheduled validation at"
				<< nextRun.toString( QStringLiteral( "dd/MM/yyyy HH:mm:ss" ) );
	}

	QTimer m_timer;
};

AccessLogValidationScheduler* s_validationScheduler = nullptr;
QDateTime s_lastTamperAlertTime;

