	}

	return analyzeAccessLogIntegrity( fileContent ).hasIssues() == false;
}

bool AccessLogWriter::appendLineToFile( const QString& filePath, const QString& line )
{
	ensureParentDirectoryExists( filePath );

	QFile file( filePath );

	if( file.open( QIODevice::Append | QIODevice::Text ) == false )
	{
		vWarning() << "[access-log-integrity] failed to append to" << filePath;
		return false;
	}

	QTextStream out( &file );
	configureLogTextStream( out );
	out << line << Qt::endl;
	return true;
}

void AccessLogWriter::appendAccessLogMessage( const QString& message )
{
	if( s_tamperLogProtector )
	{
		s_tamperLogProtector->beginProtectedBatch();
	}

	const auto line = lineWithHash( message );
	const auto accessLogPath = networkAccessLogPath();

	if( appendLineToFile( accessLogPath, line ) == false )
	{
		vWarning() << "[access-log-integrity] network access log write failed for" << accessLogPath;
	}

	if( s_tamperLogProtector )
	{
		s_tamperLogProtector->endProtectedBatch();
	}
}

bool AccessLogWriter::appendTamperAlert( const QString& detail )
{
	if( s_tamperLogProtector )
	{
		s_tamperLogProtector->beginProtectedBatch();
	}

	const auto dataHora = QDateTime::currentDateTime().toString( QStringLiteral( "dd/MM/yyyy 'Г s' HH:mm:ss" ) );
	const auto mensagem = QStringLiteral(
		"Em %1 foi detectada adulteraГ§ГЈo no arquivo acessos_veyon.log originado do equipamento [%2] [%3]. "
		"A alteraГ§ГЈo foi realizada pelo usuГЎrio [%4], identificado no Active Directory como [%5]." )
			.arg( dataHora,
				  localHostName(),
				  localIpAddress(),
				  currentAdUserLogin(),
				  currentAdUserFullName() );

	const auto tamperedLogPath = networkTamperedLogPath();
	const auto line = lineWithHash( mensagem );

	if( appendLineToFile( tamperedLogPath, line ) == false )
	{
		vWarning() << "[access-log-integrity] failed to append tamper alert to" << tamperedLogPath;
		if( s_tamperLogProtector )
		{
			s_tamperLogProtector->endProtectedBatch();
		}
		return false;
	}

	vWarning() << "[access-log-integrity]" << detail;

	if( s_tamperLogProtector )
	{
		s_tamperLogProtector->endProtectedBatch();
	}

	return true;
}

bool AccessLogWriter::recordTamperAlertForAccessLogTamper( const QString& filePath, const QString& integrityStateLabel )
{
	Q_UNUSED( integrityStateLabel )

	if( filePath != networkAccessLogPath() || QFile::exists( filePath ) == false )
	{
		return false;
	}

	QString fileContent;
	if( tryReadLogFileContent( filePath, fileContent ) == false )
	{
		return false;
	}

	const auto integrityResult = analyzeAccessLogIntegrity( fileContent );
	const auto fingerprint = sha256Hex( normalizeLogContent( fileContent ) );
	const auto globalTamperKey = QStringLiteral( "access-tamper" );

	if( integrityResult.hasIssues() == false )
	{
		vDebug() << "[access-log-integrity] skipping tamper alert: acessos_veyon hashes are valid (legitimate append)";
		auto state = loadIntegrityState();
		state.insert( QStringLiteral( "rede" ), fingerprint );
		state.insert( globalTamperKey, fingerprint );
		saveIntegrityState( state );
		if( s_tamperLogProtector )
		{
			s_tamperLogProtector->refreshBackups();
		}
		return false;
	}

	if( isTamperAlertDuplicatedOnNetwork( fingerprint ) )
	{
		vDebug() << "[access-log-integrity] skipping duplicate tamper alert for network fingerprint";
		auto state = loadIntegrityState();
		state.insert( globalTamperKey, fingerprint );
		saveIntegrityState( state );
		if( s_tamperLogProtector )
		{
			s_tamperLogProtector->refreshBackups();
		}
		return false;
	}

	auto state = loadIntegrityState();
	if( state.value( globalTamperKey ) == fingerprint ||
		state.value( integrityStateLabel ) == fingerprint )
	{
		return false;
	}

	if( s_lastTamperAlertTime.isValid() &&
		s_lastTamperAlertTime.secsTo( QDateTime::currentDateTime() ) < 5 )
	{
		return false;
	}

	bool alertWritten = appendTamperAlert( QStringLiteral( "Hash invalido na(s) linha(s) %1 do arquivo %2." )
											 .arg( integrityResult.invalidLineNumbers.join( QStringLiteral( ", " ) ),
												   integrityStateLabel ) );

	if( alertWritten == false )
	{
		return false;
	}

	saveNetworkTamperDedupState( fingerprint );
	state.insert( QStringLiteral( "rede" ), fingerprint );
	state.insert( globalTamperKey, fingerprint );
	saveIntegrityState( state );
	s_lastTamperAlertTime = QDateTime::currentDateTime();
	return true;
}

void AccessLogWriter::validateAccessLogFile( const QString& filePath, const QString& fileLabel )
{
	if( QFile::exists( filePath ) == false )
	{
		return;
	}

	QString fileContent;
	if( tryReadLogFileContent( filePath, fileContent ) == false )
	{
		appendTamperAlert( QStringLiteral( "Nao foi possivel ler o arquivo %1 (%2)." )
							 .arg( fileLabel, filePath ) );
		return;
	}

	const auto integrityResult = analyzeAccessLogIntegrity( fileContent );

	if( integrityResult.hasIssues() == false )
	{
		auto state = loadIntegrityState();
		if( state.remove( fileLabel ) )
		{
			saveIntegrityState( state );
		}
		return;
	}

	recordTamperAlertForAccessLogTamper( filePath, fileLabel );
}

