QString AccessLogWriter::networkAccessLogPath()
{
	return QDir( AccessLogPermissions::networkAccessLogDirectoryPath() )
		.filePath( QStringLiteral( "acessos_veyon.log" ) );
}

QString AccessLogWriter::networkTamperedLogPath()
{
	return QDir( AccessLogPermissions::networkTamperedLogDirectoryPath() )
		.filePath( QStringLiteral( "acessos_veyon_ad.log" ) );
}

QString AccessLogWriter::sha256Hex( const QString& message )
{
	return QString::fromLatin1(
		QCryptographicHash::hash( message.toUtf8(), QCryptographicHash::Sha256 ).toHex() );
}

QString AccessLogWriter::lineWithHash( const QString& message )
{
	return message + HashMarker() + sha256Hex( message );
}

QString AccessLogWriter::readLogFileContent( const QString& filePath )
{
	QString content;
	if( tryReadLogFileContent( filePath, content ) )
	{
		return content;
	}

	return {};
}

bool AccessLogWriter::tryReadLogFileContent( const QString& filePath, QString& content )
{
	QFile file( filePath );
	if( file.exists() == false )
	{
		content.clear();
		return true;
	}

	if( file.open( QIODevice::ReadOnly ) == false )
	{
		return false;
	}

	content = decodeLogFileBytes( file.readAll() );
	return true;
}

bool AccessLogWriter::writeLogFileContent( const QString& filePath, const QString& content )
{
	ensureParentDirectoryExists( filePath );

	QFile file( filePath );

	if( file.open( QIODevice::WriteOnly | QIODevice::Text | QIODevice::Truncate ) == false )
	{
		vWarning() << "[access-log-integrity] failed to write" << filePath << file.errorString();
		return false;
	}

	QTextStream out( &file );
	configureLogTextStream( out );
	out << content;

	if( content.isEmpty() == false && content.endsWith( QLatin1Char( '\n' ) ) == false )
	{
		out << Qt::endl;
	}

	return true;
}

bool AccessLogWriter::logContentsEqual( const QString& left, const QString& right )
{
	return normalizeLogContent( left ) == normalizeLogContent( right );
}

bool AccessLogWriter::isLegitimateProtectedLogAppend( const QString& backup, const QString& currentContent )
{
	if( logContentsEqual( backup, currentContent ) )
	{
		return true;
	}

	const auto normalizedBackup = normalizeLogContent( backup );
	const auto normalizedCurrent = normalizeLogContent( currentContent );

	if( normalizedCurrent.length() < normalizedBackup.length() )
	{
		return false;
	}

	if( normalizedBackup.isEmpty() == false &&
		normalizedCurrent.startsWith( normalizedBackup ) == false )
	{
		return false;
	}

	const auto appendedSuffix = normalizedCurrent.mid( normalizedBackup.length() );
	if( appendedSuffix.trimmed().isEmpty() )
	{
		return false;
	}

	const auto hashMarker = QStringLiteral( " | SHA256: " );
	const auto appendedLines = appendedSuffix.split( QLatin1Char( '\n' ), Qt::KeepEmptyParts );

	for( const auto& rawLine : appendedLines )
	{
		const auto line = rawLine.trimmed();
		if( line.isEmpty() )
		{
			continue;
		}

		const auto markerIndex = line.lastIndexOf( hashMarker );
		if( markerIndex < 0 )
		{
			return false;
		}

		const auto messagePart = line.left( markerIndex );
		const auto storedHash = line.mid( markerIndex + hashMarker.size() ).trimmed();
		if( storedHash.compare( AccessLogWriter::sha256Hex( messagePart ), Qt::CaseInsensitive ) != 0 )
		{
			return false;
		}
	}

	return true;
}

bool isAccessLogShareHost()
{
	const auto hostName = localHostName();
	if( hostName.compare( QStringLiteral( "DC01" ), Qt::CaseInsensitive ) == 0 )
	{
		return true;
	}

	return firstNonLoopbackIpv4() == QStringLiteral( "172.20.100.36" );
}

