bool isLoopbackIp( const QString& ip )
{
	if( ip.isEmpty() )
	{
		return true;
	}

	const QHostAddress hostAddress( ip );
	if( hostAddress.isNull() == false && hostAddress.isLoopback() )
	{
		return true;
	}

	return ip == QLatin1String( "127.0.0.1" ) ||
		   ip == QLatin1String( "::1" ) ||
		   ip == QLatin1String( "0:0:0:0:0:0:0:1" );
}

QString localIpv4()
{
	for( const auto& address : QNetworkInterface::allAddresses() )
	{
		if( address.protocol() == QAbstractSocket::IPv4Protocol && address.isLoopback() == false )
		{
			return address.toString();
		}
	}

	return {};
}

QString formatDisconnectDuration( qint64 elapsedMilliseconds )
{
	const auto totalSeconds = qMax<qint64>( 0, elapsedMilliseconds / 1000 );
	const auto hours = totalSeconds / 3600;
	const auto minutes = ( totalSeconds % 3600 ) / 60;
	const auto seconds = totalSeconds % 60;

	const QString formattedTime = QStringLiteral( "%1:%2:%3" )
			.arg( hours, 2, 10, QLatin1Char( '0' ) )
			.arg( minutes, 2, 10, QLatin1Char( '0' ) )
			.arg( seconds, 2, 10, QLatin1Char( '0' ) );

	if( hours > 0 )
	{
		return formattedTime + QStringLiteral( " horas" );
	}

	if( minutes > 0 )
	{
		return formattedTime + QStringLiteral( " minutos" );
	}

	return formattedTime + QStringLiteral( " segundos" );
}

}

bool AccessLogRecorder::shouldRecordAccess( const QString& originIp, const QString& destinationIp )
{
	if( isLoopbackIp( originIp ) || isLoopbackIp( destinationIp ) )
	{
		vDebug() << "[access-log] skipped: loopback IP in" << originIp << "->" << destinationIp;
		return false;
	}

	if( originIp == destinationIp )
	{
		vDebug() << "[access-log] skipped: self-access (same origin/destination IP)" << originIp;
		return false;
	}

	const auto localIp = localIpv4();
	if( localIp.isEmpty() == false && originIp == localIp && destinationIp == localIp )
	{
		vDebug() << "[access-log] skipped: auto-access on local machine" << localIp;
		return false;
	}

	return true;
}

