#include <windows.h>
#include <dsgetdc.h>
#include <lm.h>
#include <winldap.h>

#include <array>

#include <QStringList>

#include "AccessLogAdLookup_win.h"
#include "Logger.h"

namespace
{

std::wstring toWideString( const QString& value )
{
	return value.toStdWString();
}

QString ldapEscapeFilterValue( const QString& value )
{
	QString escaped;
	escaped.reserve( value.size() );

	for( const auto ch : value )
	{
		if( ch == QLatin1Char( '\\' ) )
		{
			escaped += QStringLiteral( "\\5c" );
		}
		else if( ch == QLatin1Char( '*' ) )
		{
			escaped += QStringLiteral( "\\2a" );
		}
		else if( ch == QLatin1Char( '(' ) )
		{
			escaped += QStringLiteral( "\\28" );
		}
		else if( ch == QLatin1Char( ')' ) )
		{
			escaped += QStringLiteral( "\\29" );
		}
		else if( ch.unicode() == 0 )
		{
			escaped += QStringLiteral( "\\00" );
		}
		else
		{
			escaped += ch;
		}
	}

	return escaped;
}

QString samAccountNameFromLogin( const QString& loginName )
{
	const auto separatorIndex = loginName.indexOf( QLatin1Char( '\\' ) );
	if( separatorIndex >= 0 )
	{
		return loginName.mid( separatorIndex + 1 );
	}

	const auto atIndex = loginName.indexOf( QLatin1Char( '@' ) );
	if( atIndex >= 0 )
	{
		return loginName.left( atIndex );
	}

	return loginName;
}

QString domainNetBiosFromLogin( const QString& loginName )
{
	const auto separatorIndex = loginName.indexOf( QLatin1Char( '\\' ) );
	if( separatorIndex > 0 )
	{
		return loginName.left( separatorIndex );
	}

	return {};
}

QString dnsDomainNameForLdap()
{
	PDOMAIN_CONTROLLER_INFO dcInfo{};
	const auto dsResult = DsGetDcName( nullptr, nullptr, nullptr, nullptr, DS_DIRECTORY_SERVICE_REQUIRED, &dcInfo );
	if( dsResult == ERROR_SUCCESS && dcInfo != nullptr && dcInfo->DomainName != nullptr )
	{
		const auto domainName = QString::fromUtf16( reinterpret_cast<const char16_t *>( dcInfo->DomainName ) );
		NetApiBufferFree( dcInfo );
		return domainName;
	}

	if( dcInfo != nullptr )
	{
		NetApiBufferFree( dcInfo );
	}

	return {};
}

QString domainNameToBaseDn( const QString& dnsDomainName )
{
	const auto parts = dnsDomainName.split( QLatin1Char( '.' ), Qt::SkipEmptyParts );
	QStringList dnParts;
	dnParts.reserve( parts.size() );

	for( const auto& part : parts )
	{
		dnParts.append( QStringLiteral( "DC=" ) + part );
	}

	return dnParts.join( QLatin1Char( ',' ) );
}

QString resolveDomainController( const QString& domainName )
{
	const auto domainNamePointer = domainName.isEmpty() ? nullptr : toWideString( domainName ).c_str();

	PDOMAIN_CONTROLLER_INFO dcInfo{};
	const auto dsResult = DsGetDcName( nullptr, domainNamePointer, nullptr, nullptr, DS_DIRECTORY_SERVICE_REQUIRED, &dcInfo );
	if( dsResult == ERROR_SUCCESS && dcInfo != nullptr && dcInfo->DomainControllerName != nullptr )
	{
		auto dcName = QString::fromUtf16( reinterpret_cast<const char16_t *>( dcInfo->DomainControllerName ) );
		NetApiBufferFree( dcInfo );
		return dcName.remove( QLatin1Char( '\\' ) );
	}

	if( dcInfo != nullptr )
	{
		NetApiBufferFree( dcInfo );
	}

	LPBYTE outBuffer = nullptr;
	const auto netResult = NetGetDCName( nullptr, domainNamePointer, &outBuffer );
	if( netResult == NERR_Success && outBuffer != nullptr )
	{
		const auto dcName = QString::fromUtf16( reinterpret_cast<const char16_t *>( outBuffer ) );
		NetApiBufferFree( outBuffer );
		return dcName;
	}

	return {};
}

QString readLdapAttribute( LDAP* ldapConnection, LDAPMessage* entry, const wchar_t* attributeName )
{
	const auto values = ldap_get_valuesW( ldapConnection, entry, const_cast<PWCHAR>( attributeName ) );
	if( values == nullptr || values[0] == nullptr )
	{
		if( values != nullptr )
		{
			ldap_value_freeW( values );
		}

		return {};
	}

	const auto value = QString::fromWCharArray( values[0] ).trimmed();
	ldap_value_freeW( values );

	return value;
}

}

QString accessLogLookupDomainUserDisplayName( const QString& loginName )
{
	const auto samAccountName = samAccountNameFromLogin( loginName );
	if( samAccountName.isEmpty() )
	{
		return {};
	}

	const auto dc = resolveDomainController( domainNetBiosFromLogin( loginName ) );
	if( dc.isEmpty() )
	{
		vWarning() << "[access-log-integrity] could not resolve domain controller for LDAP lookup of" << samAccountName;
		return {};
	}

	const auto baseDn = domainNameToBaseDn( dnsDomainNameForLdap() );
	if( baseDn.isEmpty() )
	{
		vWarning() << "[access-log-integrity] could not resolve LDAP base DN for user lookup of" << samAccountName;
		return {};
	}

	const auto dcWide = toWideString( dc );
	const auto baseDnWide = toWideString( baseDn );
	const auto filter = QStringLiteral( "(&(objectCategory=person)(objectClass=user)(sAMAccountName=%1))" )
							.arg( ldapEscapeFilterValue( samAccountName ) );
	const auto filterWide = toWideString( filter );

	LDAP* ldapConnection = ldap_initW( const_cast<PWCHAR>( dcWide.c_str() ), LDAP_PORT );
	if( ldapConnection == nullptr )
	{
		vWarning() << "[access-log-integrity] ldap_initW failed for DC" << dc;
		return {};
	}

	const ULONG ldapVersion = LDAP_VERSION3;
	ldap_set_option( ldapConnection, LDAP_OPT_PROTOCOL_VERSION, &ldapVersion );

	const auto bindResult = ldap_bind_s( ldapConnection, nullptr, nullptr, LDAP_AUTH_NEGOTIATE );
	if( bindResult != LDAP_SUCCESS )
	{
		vWarning() << "[access-log-integrity] ldap_bind_s failed for DC" << dc << "with code" << bindResult;
		ldap_unbind( ldapConnection );
		return {};
	}

	const wchar_t* attributes[] = { L"displayName", L"cn", nullptr };

	LDAPMessage* searchResult = nullptr;
	const auto searchResultCode = ldap_search_sW( ldapConnection,
												  const_cast<PWCHAR>( baseDnWide.c_str() ),
												  LDAP_SCOPE_SUBTREE,
												  const_cast<PWCHAR>( filterWide.c_str() ),
												  const_cast<PWCHAR *>( attributes ),
												  0,
												  &searchResult );

	QString fullName;
	if( searchResultCode == LDAP_SUCCESS && searchResult != nullptr )
	{
		const auto firstEntry = ldap_first_entry( ldapConnection, searchResult );
		if( firstEntry != nullptr )
		{
			fullName = readLdapAttribute( ldapConnection, firstEntry, L"displayName" );
			if( fullName.isEmpty() )
			{
				fullName = readLdapAttribute( ldapConnection, firstEntry, L"cn" );
			}
		}

		ldap_msgfree( searchResult );
	}
	else
	{
		vWarning() << "[access-log-integrity] ldap_search_sW failed for user" << samAccountName
				   << "with code" << searchResultCode;
	}

	ldap_unbind( ldapConnection );

	return fullName;
}

