QPixmap drawShieldIcon( int size, const QColor& shieldColor, const QColor& lockColor, int lockScalePercent = 35 )
{
	QPixmap pixmap( size, size );
	pixmap.fill( Qt::transparent );

	QPainter painter( &pixmap );
	painter.setRenderHint( QPainter::Antialiasing, true );

	QPainterPath shieldPath;
	const auto w = static_cast<qreal>( size );
	const auto h = static_cast<qreal>( size );
	shieldPath.moveTo( w * 0.5, h * 0.06 );
	shieldPath.lineTo( w * 0.88, h * 0.22 );
	shieldPath.lineTo( w * 0.82, h * 0.72 );
	shieldPath.quadTo( w * 0.5, h * 0.96, w * 0.18, h * 0.72 );
	shieldPath.lineTo( w * 0.12, h * 0.22 );
	shieldPath.closeSubpath();

	painter.setPen( Qt::NoPen );
	painter.setBrush( shieldColor );
	painter.drawPath( shieldPath );

	const auto lockSize = size * lockScalePercent / 100;
	const auto lockX = ( size - lockSize ) / 2;
	const auto lockY = size * 0.38;

	painter.setBrush( lockColor );
	painter.drawRoundedRect( QRectF( lockX + lockSize * 0.22, lockY, lockSize * 0.56, lockSize * 0.52 ), 3, 3 );
	painter.drawChord( QRectF( lockX, lockY - lockSize * 0.28, lockSize, lockSize * 0.62 ), 0, 180 * 16 );

	return pixmap;
}

QPixmap drawEyeIcon( int size, const QColor& color )
{
	QPixmap pixmap( size, size );
	pixmap.fill( Qt::transparent );

	QPainter painter( &pixmap );
	painter.setRenderHint( QPainter::Antialiasing, true );
	painter.setPen( QPen( color, 1.6 ) );
	painter.setBrush( Qt::NoBrush );
	painter.drawEllipse( QRectF( size * 0.12, size * 0.28, size * 0.76, size * 0.44 ) );
	painter.setBrush( color );
	painter.setPen( Qt::NoPen );
	painter.drawEllipse( QRectF( size * 0.38, size * 0.40, size * 0.24, size * 0.24 ) );

	return pixmap;
}

QLabel* createIconLabel( const QPixmap& pixmap, QWidget* parent )
{
	auto* label = new QLabel( parent );
	label->setPixmap( pixmap );
	label->setAlignment( Qt::AlignCenter );
	return label;
}

