QString trayIconResourcePath( SystemTrayIcon::StatusIndicator status )
{
	switch( status )
	{
	case SystemTrayIcon::StatusIndicator::Idle:
		return QStringLiteral( ":/core/tray-icons/idle.png" );
	case SystemTrayIcon::StatusIndicator::Connecting:
		return QStringLiteral( ":/core/tray-icons/connecting.png" );
	case SystemTrayIcon::StatusIndicator::Authenticating:
		return QStringLiteral( ":/core/tray-icons/authenticating.png" );
	case SystemTrayIcon::StatusIndicator::Connected:
	case SystemTrayIcon::StatusIndicator::Active:
		return QStringLiteral( ":/core/tray-icons/active.png" );
	case SystemTrayIcon::StatusIndicator::Monitoring:
		return QStringLiteral( ":/core/tray-icons/monitoring.png" );
	case SystemTrayIcon::StatusIndicator::Error:
		return QStringLiteral( ":/core/tray-icons/error.png" );
	}

	return QStringLiteral( ":/core/tray-icons/idle.png" );
}

bool isEdgeBackgroundPixel( const QRgb pixel, int threshold )
{
	return qRed( pixel ) <= threshold && qGreen( pixel ) <= threshold && qBlue( pixel ) <= threshold;
}

QImage removeEdgeConnectedBackground( const QImage& input, int threshold = 42 )
{
	QImage image = input.convertToFormat( QImage::Format_ARGB32 );
	const int width = image.width();
	const int height = image.height();
	if( width <= 0 || height <= 0 )
	{
		return {};
	}

	QVector<bool> visited( width * height, false );
	QQueue<QPoint> queue;

	const auto enqueue = [&]( int x, int y )
	{
		if( x < 0 || x >= width || y < 0 || y >= height )
		{
			return;
		}

		const auto index = y * width + x;
		if( visited[index] || isEdgeBackgroundPixel( image.pixel( x, y ), threshold ) == false )
		{
			return;
		}

		visited[index] = true;
		queue.enqueue( QPoint( x, y ) );
	};

	for( int x = 0; x < width; ++x )
	{
		enqueue( x, 0 );
		enqueue( x, height - 1 );
	}

	for( int y = 0; y < height; ++y )
	{
		enqueue( 0, y );
		enqueue( width - 1, y );
	}

	while( queue.isEmpty() == false )
	{
		const auto point = queue.dequeue();
		enqueue( point.x() - 1, point.y() );
		enqueue( point.x() + 1, point.y() );
		enqueue( point.x(), point.y() - 1 );
		enqueue( point.x(), point.y() + 1 );
	}

	QImage output( width, height, QImage::Format_ARGB32 );
	output.fill( Qt::transparent );

	for( int y = 0; y < height; ++y )
	{
		for( int x = 0; x < width; ++x )
		{
			if( visited[y * width + x] == false )
			{
				output.setPixel( x, y, image.pixel( x, y ) );
			}
		}
	}

	return output;
}

QImage trimTransparentImage( const QImage& input )
{
	const auto width = input.width();
	const auto height = input.height();
	if( width <= 0 || height <= 0 )
	{
		return {};
	}

	auto minX = width;
	auto minY = height;
	auto maxX = -1;
	auto maxY = -1;

	for( int y = 0; y < height; ++y )
	{
		for( int x = 0; x < width; ++x )
		{
			if( qAlpha( input.pixel( x, y ) ) > 8 )
			{
				minX = qMin( minX, x );
				minY = qMin( minY, y );
				maxX = qMax( maxX, x );
				maxY = qMax( maxY, y );
			}
		}
	}

	if( maxX < minX || maxY < minY )
	{
		return {};
	}

	return input.copy( minX, minY, maxX - minX + 1, maxY - minY + 1 );
}

QImage prepareTrayIconSource( const QImage& input )
{
	const auto cleaned = removeEdgeConnectedBackground( input );
	const auto trimmed = trimTransparentImage( cleaned );
	if( trimmed.isNull() )
	{
		return {};
	}

	return trimmed.scaled( 512, 512, Qt::KeepAspectRatio, Qt::SmoothTransformation );
}

qreal trayIconRenderDpr( qreal devicePixelRatio )
{
	return qMax( devicePixelRatio, 2.0 );
}

const QImage& trayIconSourceImage( SystemTrayIcon::StatusIndicator status )
{
	static QHash<int, QImage> sources;

	const auto key = static_cast<int>( status );
	const auto existing = sources.find( key );
	if( existing != sources.end() )
	{
		return existing.value();
	}

	QImage image( trayIconResourcePath( status ) );
	if( image.isNull() )
	{
		vWarning() << "[tray] failed to load icon resource for status" << key;
	}
	else
	{
		image = prepareTrayIconSource( image );
		if( image.isNull() )
		{
			vWarning() << "[tray] failed to prepare icon resource for status" << key;
		}
	}

	sources.insert( key, image );
	return sources[key];
}

qreal trayIconDevicePixelRatio()
{
	if( const auto* screen = QGuiApplication::primaryScreen() )
	{
		return qMax( 1.0, screen->devicePixelRatio() );
	}

	return 1.0;
}

qreal trayDpiAtPoint( const QPoint& point )
{
	if( const auto* screen = QGuiApplication::screenAt( point ) )
	{
		return qMax( 1.0, screen->devicePixelRatio() );
	}

	return trayIconDevicePixelRatio();
}

QPixmap renderTrayStatusPixmap( SystemTrayIcon::StatusIndicator status, int logicalSize, qreal devicePixelRatio )
{
	const auto& sourceImage = trayIconSourceImage( status );
	if( sourceImage.isNull() )
	{
		return {};
	}

	const qreal dpr = qMax( devicePixelRatio, 1.0 );
	const int physicalSize = qMax( 1, qRound( logicalSize * dpr ) );
	const int renderSize = qMax( physicalSize, qRound( logicalSize * trayIconRenderDpr( dpr ) ) );
	const int padding = qMax( 1, qRound( renderSize * 0.10 ) );
	const int drawableSize = qMax( 1, renderSize - padding * 2 );

	const auto scaledImage = sourceImage.scaled( drawableSize, drawableSize,
												 Qt::KeepAspectRatio,
												 Qt::SmoothTransformation );

	QImage rendered( renderSize, renderSize, QImage::Format_ARGB32 );
	rendered.fill( Qt::transparent );

	{
		QPainter painter( &rendered );
		painter.setRenderHint( QPainter::Antialiasing, true );
		painter.setRenderHint( QPainter::SmoothPixmapTransform, true );

		const int x = ( renderSize - scaledImage.width() ) / 2;
		const int y = ( renderSize - scaledImage.height() ) / 2;
		painter.drawImage( x, y, scaledImage );
	}

	QPixmap pixmap = QPixmap::fromImage(
		rendered.scaled( physicalSize, physicalSize, Qt::KeepAspectRatio, Qt::SmoothTransformation ) );
	pixmap.setDevicePixelRatio( dpr );

	return pixmap;
}

SystemTrayIcon::StatusIndicator hoverStatusFor( SystemTrayIcon::StatusIndicator trayStatus )
{
	switch( trayStatus )
	{
	case SystemTrayIcon::StatusIndicator::Connected:
	case SystemTrayIcon::StatusIndicator::Active:
		return SystemTrayIcon::StatusIndicator::Monitoring;
	default:
		return trayStatus;
	}
}

QIcon buildStatusIcon( SystemTrayIcon::StatusIndicator status, const QImage& overlayIcon )
{
	QIcon icon;
	const auto screenDpr = trayIconDevicePixelRatio();

	QList<qreal> devicePixelRatios = {1.0, 1.25, 1.5, 1.75, 2.0};
	if( devicePixelRatios.contains( screenDpr ) == false )
	{
		devicePixelRatios.append( screenDpr );
		std::sort( devicePixelRatios.begin(), devicePixelRatios.end() );
	}

	for( const auto devicePixelRatio : devicePixelRatios )
	{
		for( const auto size : {16, 20, 22, 24, 32, 48, 64, 128} )
		{
			auto pixmap = renderTrayStatusPixmap( status, size, devicePixelRatio );
			if( pixmap.isNull() )
			{
				continue;
			}

			if( overlayIcon.isNull() == false && qAbs( devicePixelRatio - screenDpr ) < 0.01 )
			{
				QPainter painter( &pixmap );
				painter.setRenderHint( QPainter::SmoothPixmapTransform, true );
				const auto logicalPixmapSize = qRound( pixmap.width() / pixmap.devicePixelRatio() );
				painter.drawImage( 0, 0, overlayIcon.scaled( logicalPixmapSize, logicalPixmapSize,
															   Qt::KeepAspectRatio, Qt::SmoothTransformation ) );
			}

			icon.addPixmap( pixmap );
		}
	}

	return icon;
}

bool isTrayHoverDarkMode()
{
#if QT_VERSION >= QT_VERSION_CHECK(6, 5, 0)
	if( QGuiApplication::styleHints() &&
		QGuiApplication::styleHints()->colorScheme() == Qt::ColorScheme::Dark )
	{
		return true;
	}
#endif

	return VeyonCore::useDarkMode();
