		   status == SystemTrayIcon::StatusIndicator::Active;
}

class TrayHoverPopup : public QWidget
{
public:
	static constexpr int HoverIconLogicalSize = 48;

	explicit TrayHoverPopup()
	{
		setWindowFlags( Qt::ToolTip | Qt::FramelessWindowHint | Qt::WindowStaysOnTopHint );
		setAttribute( Qt::WA_ShowWithoutActivating );
		setAttribute( Qt::WA_TranslucentBackground, false );

		auto* layout = new QHBoxLayout( this );
		layout->setContentsMargins( 12, 10, 12, 10 );
		layout->setSpacing( 10 );

		m_iconLabel = new QLabel( this );
		m_iconLabel->setFixedSize( HoverIconLogicalSize, HoverIconLogicalSize );
		m_iconLabel->setScaledContents( false );
		m_iconLabel->setAlignment( Qt::AlignCenter );

		m_textLabel = new QLabel( this );
		m_textLabel->setWordWrap( true );
		m_textLabel->setMinimumWidth( 260 );
		m_textLabel->setMaximumWidth( 420 );
		QFont textFont = m_textLabel->font();
		textFont.setPointSize( 9 );
		m_textLabel->setFont( textFont );

		layout->addWidget( m_iconLabel );
		layout->addWidget( m_textLabel, 1 );

		applyColorScheme();

#if QT_VERSION >= QT_VERSION_CHECK(6, 5, 0)
		if( QGuiApplication::styleHints() )
		{
			connect( QGuiApplication::styleHints(), &QStyleHints::colorSchemeChanged,
					 this, [this]() {
				applyColorScheme();
			} );
		}
#endif
	}

	void updateContent( SystemTrayIcon::StatusIndicator hoverStatus, const QString& text )
	{
		applyColorScheme();

		const auto effectiveDpr = qMax( devicePixelRatioF(), trayDpiAtPoint( QCursor::pos() ) );
		const auto pixmap = renderTrayStatusPixmap( hoverStatus, HoverIconLogicalSize, effectiveDpr );
		m_iconLabel->setPixmap( pixmap.isNull() ? QPixmap() : pixmap );

		QFont textFont = m_textLabel->font();
		textFont.setPointSizeF( 9.0 * effectiveDpr );
		m_textLabel->setFont( textFont );

		if( hoverStatus == SystemTrayIcon::StatusIndicator::Idle )
		{
			m_textLabel->setTextFormat( Qt::RichText );
			m_textLabel->setText( ComputerSupportInfo::idleTrayHoverHtml() );
		}
		else
		{
			m_textLabel->setTextFormat( Qt::PlainText );
			m_textLabel->setText( text );
		}

		adjustSize();
	}

	void showNearTray( QSystemTrayIcon* trayIcon )
	{
		if( trayIcon == nullptr )
		{
			return;
		}

		applyColorScheme();

		const auto trayGeometry = trayIcon->geometry();
		if( trayGeometry.isValid() && trayGeometry.isEmpty() == false )
		{
			const auto popupSize = sizeHint();
			auto x = trayGeometry.center().x() - popupSize.width() / 2;
			auto y = trayGeometry.top() - popupSize.height() - 8;

			const auto screen = QGuiApplication::screenAt( trayGeometry.center() );
			if( screen )
			{
				const auto available = screen->availableGeometry();
				x = qBound( available.left() + 4, x, available.right() - popupSize.width() - 4 );
				if( y < available.top() )
				{
					y = trayGeometry.bottom() + 8;
				}
			}

			move( x, y );
		}
		else
		{
			showNearCursor();
		}

		show();
	}

	void showNearCursor()
	{
		applyColorScheme();

		const auto cursorPos = QCursor::pos();
		const auto popupSize = sizeHint();
		move( cursorPos.x() - popupSize.width() / 2, cursorPos.y() - popupSize.height() - 16 );
	}

private:
	void applyColorScheme()
	{
		if( isTrayHoverDarkMode() )
		{
			setStyleSheet( QStringLiteral(
				"TrayHoverPopup { background-color: #1f2933; border: 1px solid #4a5568; border-radius: 8px; }"
				"QLabel { color: #f5f7fa; background: transparent; }" ) );
		}
		else
		{
			setStyleSheet( QStringLiteral(
				"TrayHoverPopup { background-color: #f5f7fa; border: 1px solid #b8c2cc; border-radius: 8px; }"
				"QLabel { color: #1f2933; background: transparent; }" ) );
		}
	}

	QLabel* m_iconLabel = nullptr;
	QLabel* m_textLabel = nullptr;
};

TrayHoverPopup* hoverPopupWidget( QWidget* widget )
{
	return static_cast<TrayHoverPopup*>( widget );
}

bool isTrayFeatureWorkerProcess( const Feature& trayFeature )
{
	const auto arguments = QCoreApplication::arguments();
	return arguments.size() >= 2 && Feature::Uid{arguments[1]} == trayFeature.uid();
}

