constexpr int SupportInfoHotkeyId = 0xF090;

QPointer<SystemTrayIcon> s_supportInfoTrayIcon;
bool s_supportInfoHotkeyRegistered = false;

class SupportInfoHotkeyFilter final : public QAbstractNativeEventFilter
{
public:
	bool nativeEventFilter( const QByteArray& eventType, void* message, qintptr* result ) override
	{
		Q_UNUSED( result )

		if( eventType != "windows_generic_MSG" && eventType != "windows_dispatcher_MSG" )
		{
			return false;
		}

		const auto* msg = static_cast<MSG*>( message );
		if( msg->message == WM_HOTKEY && msg->wParam == SupportInfoHotkeyId )
		{
			vWarning() << "[support-info][f9] WM_HOTKEY received";
			if( s_supportInfoTrayIcon )
			{
				QMetaObject::invokeMethod( s_supportInfoTrayIcon, "showSupportInfoDialog", Qt::DirectConnection );
			}
			else
			{
				vWarning() << "[support-info][f9] hotkey ignored - tray icon pointer is null";
			}

			return true;
		}

		return false;
	}
};

SupportInfoHotkeyFilter* s_supportInfoHotkeyFilter = nullptr;

}
#endif

