SystemTrayIcon::SystemTrayIcon( QObject* parent ) :
	QObject( parent ),
	m_systemTrayIconFeature( Feature( QLatin1String( staticMetaObject.className() ),
									  Feature::Flag::Session | Feature::Flag::Service | Feature::Flag::Worker | Feature::Flag::Builtin,
									  Feature::Uid( "8e997d84-ebb9-430f-8f72-d45d9821963d" ),
									  Feature::Uid(),
									  tr( "System tray icon"), {}, {} ) ),
	m_hidden(VeyonCore::config().isTrayIconHidden())
{
	if( VeyonCore::component() == VeyonCore::Component::Worker &&
		isTrayFeatureWorkerProcess( m_systemTrayIconFeature ) )
	{
		AccessLogWriter::startNetworkMirrorScheduler( this );
		setupTamperLogPasswordServer();
		setupSupportInfoHotkey();
	}
}



void SystemTrayIcon::ensureTrayIcon()
{
	if( m_hidden )
	{
		// #region debug-point E:tray-hidden
		vDebug() << "[DEBUG][tray-runtime-state] ensureTrayIcon skipped because tray is hidden";
		// #endregion
		return;
	}

	const bool trayCreated = s_sharedSystemTrayIcon.isNull();
	if( trayCreated )
	{
		s_sharedSystemTrayIcon = new QSystemTrayIcon( qApp );
		vDebug() << "[tray][worker] created shared tray icon";
		// #region debug-point F:tray-created
		vDebug() << "[DEBUG][tray-runtime-state] created shared tray icon"
				 << "visible" << s_sharedSystemTrayIcon->isVisible();
		// #endregion

		static bool trayDpiRefreshHooked = false;
		if( trayDpiRefreshHooked == false )
		{
			trayDpiRefreshHooked = true;

			const auto refreshTrayIcons = []() {
				if( s_sharedSystemTrayIcon.isNull() )
				{
					return;
				}

				QImage overlayIcon;
				if( s_sharedOverlayIconUrl.isEmpty() == false )
				{
					overlayIcon.load( s_sharedOverlayIconUrl );
				}

				const auto trayIcon = buildStatusIcon( s_sharedStatusIndicator, overlayIcon );
				const auto hoverIcon = buildStatusIcon( hoverStatusFor( s_sharedStatusIndicator ), {} );
				s_sharedTrayIcon = trayIcon;
				s_sharedHoverIcon = hoverIcon;
				s_sharedSystemTrayIcon->setIcon( trayIcon );
				if( qApp )
				{
					qApp->setWindowIcon( hoverIcon );
				}
			};

			const auto hookScreen = [refreshTrayIcons]( QScreen* screen ) {
				if( screen == nullptr || qApp == nullptr )
				{
					return;
				}

				QObject::connect( screen, &QScreen::logicalDotsPerInchChanged,
								  qApp, refreshTrayIcons, Qt::UniqueConnection );
			};

			hookScreen( QGuiApplication::primaryScreen() );
			QObject::connect( qApp, &QGuiApplication::screenAdded, qApp, hookScreen );

			for( auto* screen : QGuiApplication::screens() )
			{
				hookScreen( screen );
			}
		}
	}

	m_systemTrayIcon = s_sharedSystemTrayIcon.data();
	m_statusIndicator = s_sharedStatusIndicator;
	m_toolTipText = s_sharedToolTipText;
	m_overlayIconUrl = s_sharedOverlayIconUrl;
	// #region debug-point G:tray-bound
	vDebug() << "[DEBUG][tray-runtime-state] ensureTrayIcon bound shared tray"
			 << "status" << static_cast<int>( m_statusIndicator )
			 << "tooltip" << m_toolTipText
			 << "overlay" << m_overlayIconUrl;
	// #endregion

	if( trayCreated )
	{
		updateIcon( m_overlayIconUrl );
		applyTrayToolTip();

		if( m_systemTrayIcon->isVisible() == false )
		{
			m_systemTrayIcon->show();
		}

		ensureHoverPopup();

		if( VeyonCore::component() == VeyonCore::Component::Worker &&
			isTrayFeatureWorkerProcess( m_systemTrayIconFeature ) )
		{
			setupSupportInfoHotkey();
		}
	}
}



void SystemTrayIcon::ensureHoverPopup()
{
	if( m_hoverPopup == nullptr )
	{
		m_hoverPopup = new TrayHoverPopup();
	}

	if( m_hoverTimer == nullptr )
	{
		m_hoverTimer = new QTimer( this );
		m_hoverTimer->setInterval( 150 );
		connect( m_hoverTimer, &QTimer::timeout, this, &SystemTrayIcon::checkTrayHover );
	}

	if( m_hoverTimer->isActive() == false )
	{
		m_hoverTimer->start();
	}
}



void SystemTrayIcon::applyTrayToolTip()
{
	if( m_systemTrayIcon )
	{
		// O popup customizado exibe icone + texto; suprime tooltip nativo do Windows.
		m_systemTrayIcon->setToolTip( {} );
	}
}



void SystemTrayIcon::checkTrayHover()
{
	if( m_systemTrayIcon == nullptr || m_systemTrayIcon->isVisible() == false )
	{
		if( m_hoverPopup )
		{
			m_hoverPopup->hide();
		}
		return;
	}

	const auto trayGeometry = m_systemTrayIcon->geometry();
	const bool geometryReady = trayGeometry.isValid() && trayGeometry.isEmpty() == false;

	QRect hoverRect = trayGeometry;
	if( geometryReady == false )
	{
		const auto screen = QGuiApplication::primaryScreen();
		if( screen )
		{
			const auto workArea = screen->availableGeometry();
			hoverRect = QRect( workArea.right() - 280, workArea.bottom() - 52, 280, 52 );
		}
	}

	const bool cursorOverTray = hoverRect.contains( QCursor::pos() );

	if( cursorOverTray )
	{
		if( m_hoverPopup == nullptr )
		{
			m_hoverPopup = new TrayHoverPopup();
		}

		hoverPopupWidget( m_hoverPopup )->updateContent( hoverStatusFor( s_sharedStatusIndicator ), s_sharedToolTipText );
		hoverPopupWidget( m_hoverPopup )->showNearTray( m_systemTrayIcon );
	}
	else if( m_hoverPopup && m_hoverPopup->isVisible() )
	{
		m_hoverPopup->hide();
	}
}



