bool SystemTrayIcon::handleFeatureMessage( VeyonServerInterface& server,
										  const MessageContext& messageContext,
										  const FeatureMessage& message )
{
	Q_UNUSED(messageContext)

	if( m_systemTrayIconFeature.uid() == message.featureUid() )
	{
		// forward message to worker
		server.featureWorkerManager().sendMessageToUnmanagedSessionWorker( message );
		return true;
	}

	return false;
}



bool SystemTrayIcon::handleFeatureMessage( VeyonWorkerInterface& worker, const FeatureMessage& message )
{
	Q_UNUSED( worker )

	if( message.featureUid() != m_systemTrayIconFeature.uid() )
	{
		return false;
	}

	ensureTrayIcon();
	// #region debug-point H:worker-message-received
	vWarning() << "[DEBUG][tray-runtime-state] worker received tray message"
			   << "command" << static_cast<int>( message.command<FeatureCommand>() );
	// #endregion

	switch(message.command<FeatureCommand>())
	{
	case FeatureCommand::SetToolTip:
		if( m_systemTrayIcon )
		{
			m_toolTipText = message.argument( Argument::ToolTipText ).toString();
			s_sharedToolTipText = m_toolTipText;
			// debug-point tray-tooltip-received
			vWarning() << "[tray][worker] applying tooltip" << m_toolTipText;
			// #region debug-point I:tooltip-applied
			vWarning() << "[DEBUG][tray-runtime-state] applying tooltip to visible tray"
					   << "tooltip" << m_toolTipText;
			// #endregion
			applyTrayToolTip();
			if( m_hoverPopup && m_hoverPopup->isVisible() )
			{
				hoverPopupWidget( m_hoverPopup )->updateContent( hoverStatusFor( s_sharedStatusIndicator ), s_sharedToolTipText );
			}
		}
		return true;

	case FeatureCommand::ShowMessage:
		if( m_systemTrayIcon )
		{
			m_systemTrayIcon->showMessage( message.argument( Argument::MessageTitle ).toString(),
										   message.argument( Argument::MessageText ).toString() );
		}
		else
		{
			QMessageBox::information( nullptr,
									  message.argument( Argument::MessageTitle ).toString(),
									  message.argument( Argument::MessageText ).toString() );
			QCoreApplication::instance()->quit();
		}
		return true;

	case FeatureCommand::SetOverlayIcon:
		m_overlayIconUrl = message.argument( Argument::OverlayIconUrl ).toString();
		s_sharedOverlayIconUrl = m_overlayIconUrl;
		// #region debug-point J:overlay-applied
		vDebug() << "[DEBUG][tray-runtime-state] applying overlay"
				 << "overlay" << m_overlayIconUrl;
		// #endregion
		updateIcon( m_overlayIconUrl );
		return true;

	case FeatureCommand::SetStatusIndicator:
	{
		const auto newStatus = static_cast<StatusIndicator>( message.argument( Argument::StatusIndicator ).toInt() );
		const auto previousStatus = m_statusIndicator;
		m_statusIndicator = newStatus;
		s_sharedStatusIndicator = m_statusIndicator;
		// debug-point tray-status-received
		vWarning() << "[tray][worker] applying status" << static_cast<int>( m_statusIndicator );
		// #region debug-point K:status-applied
		vWarning() << "[DEBUG][tray-runtime-state] applying status to visible tray"
				   << "status" << static_cast<int>( m_statusIndicator );
		// #endregion
		if( isActiveSessionTrayStatus( previousStatus ) && isActiveSessionTrayStatus( newStatus ) )
		{
			return true;
		}
		updateIcon();
		return true;
	}

	case FeatureCommand::PromptTamperLogPassword:
		showTamperLogPasswordDialog();
		return true;

	case FeatureCommand::ShowVersionAlert:
		vWarning() << "[cimed-version-alert] worker showing version alert dialog for"
				   << message.argument( Argument::VersionAlertOriginIp ).toString()
				   << message.argument( Argument::VersionAlertAdUser ).toString();
		qApp->setQuitOnLastWindowClosed( false );
		CimedVersionAlertDialog::showAlert( message.argument( Argument::VersionAlertOriginIp ).toString(),
											message.argument( Argument::VersionAlertOriginHost ).toString(),
											message.argument( Argument::VersionAlertAdUser ).toString(),
											message.argument( Argument::VersionAlertAdDisplayName ).toString(),
											message.argument( Argument::VersionAlertDetectedVersion ).toString() );
		return true;

	default:
		break;
	}

	return false;
}



void SystemTrayIcon::updateIcon(const QString& overlayIconUrl)
{
	if (m_systemTrayIcon)
	{
		// #region debug-point L:update-icon-entry
		vDebug() << "[DEBUG][tray-runtime-state] updateIcon"
				 << "status" << static_cast<int>( s_sharedStatusIndicator )
				 << "overlay" << overlayIconUrl
				 << "tooltip" << s_sharedToolTipText;
		// #endregion
		QImage overlayIcon;
		if (overlayIconUrl.isEmpty() == false)
		{
			overlayIcon.load(overlayIconUrl);
		}

		const auto trayIcon = buildStatusIcon( s_sharedStatusIndicator, overlayIcon );
		const auto hoverStatus = hoverStatusFor( s_sharedStatusIndicator );
		const auto hoverIcon = buildStatusIcon( hoverStatus, {} );
		s_sharedTrayIcon = trayIcon;
		s_sharedHoverIcon = hoverIcon;
		const QString iconVariant = hoverStatus == s_sharedStatusIndicator
			? QStringLiteral( "same-as-tray" )
			: QStringLiteral( "monitoring-on-hover" );

		m_systemTrayIcon->setIcon( trayIcon );
		qApp->setWindowIcon( hoverIcon );
		applyTrayToolTip();
		if( m_hoverPopup && m_hoverPopup->isVisible() )
		{
			hoverPopupWidget( m_hoverPopup )->updateContent( hoverStatusFor( s_sharedStatusIndicator ), s_sharedToolTipText );
		}
		// #region debug-point N:hover-icon-source
		vWarning() << "[DEBUG][hover-icon-source] tray and hover icons applied"
				   << "trayStatus" << static_cast<int>( s_sharedStatusIndicator )
				   << "hoverStatus" << static_cast<int>( hoverStatus )
				   << "variant" << iconVariant
				   << "tooltipPreview" << s_sharedToolTipText.left( 80 );
		// #endregion
		// #region debug-point O:tray-icon-applied
		const auto trayAvailableSizes = m_systemTrayIcon->icon().availableSizes();
		const auto windowAvailableSizes = qApp->windowIcon().availableSizes();
		const auto trayFirstSize = trayAvailableSizes.isEmpty() ? QSize{} : trayAvailableSizes.constFirst();
		const auto windowFirstSize = windowAvailableSizes.isEmpty() ? QSize{} : windowAvailableSizes.constFirst();

		vWarning() << "[DEBUG][hover-status-icon] tray icon applied"
				   << "status" << static_cast<int>( s_sharedStatusIndicator )
				   << "trayIconIsNull" << m_systemTrayIcon->icon().isNull()
				   << "trayIconSizeCount" << trayAvailableSizes.count()
				   << "trayIconFirstSize" << trayFirstSize
				   << "windowIconIsNull" << qApp->windowIcon().isNull()
				   << "windowIconSizeCount" << windowAvailableSizes.count()
				   << "windowIconFirstSize" << windowFirstSize;
		// #endregion
		// #region debug-point M:update-icon-done
		vDebug() << "[DEBUG][tray-runtime-state] setIcon finished"
				 << "trayStatus" << static_cast<int>( s_sharedStatusIndicator )
				 << "hoverStatus" << static_cast<int>( hoverStatus )
				 << "sizes" << QStringLiteral("16,22,32,48,64,128");
		// #endregion
	}
}



