void SystemTrayIcon::showTamperLogPasswordDialog()
{
	static bool s_dialogOpen = false;
	if( s_dialogOpen )
	{
		return;
	}

	s_dialogOpen = true;

	TamperLogPasswordDialog dialog( QApplication::activeWindow() );
	dialog.raise();
	dialog.activateWindow();

	if( dialog.exec() == QDialog::Accepted )
	{
		TamperLogProtector::writeTamperResponse( QStringLiteral( "accept" ) );
		vInfo() << "[tamper-log-protection] password accepted";
	}
	else
	{
		TamperLogProtector::writeTamperResponse( QStringLiteral( "reject" ) );
		vInfo() << "[tamper-log-protection] password rejected";
	}

	s_dialogOpen = false;
}



void SystemTrayIcon::setupTamperLogPasswordServer()
{
	if( m_tamperLogPasswordServer )
	{
		return;
	}

	const auto arguments = QCoreApplication::arguments();
	if( arguments.size() < 2 || Feature::Uid{arguments[1]} != m_systemTrayIconFeature.uid() )
	{
		return;
	}

	m_tamperLogPasswordServer = new QLocalServer( this );
	QLocalServer::removeServer( localTamperLogServerName() );
	if( m_tamperLogPasswordServer->listen( localTamperLogServerName() ) )
	{
		connect( m_tamperLogPasswordServer, &QLocalServer::newConnection,
				 this, &SystemTrayIcon::handleTamperLogPasswordRequest );
		vInfo() << "[tamper-log-protection] listening on" << localTamperLogServerName();
	}
	else
	{
		vWarning() << "[tamper-log-protection] could not listen on" << localTamperLogServerName();
	}
}



void SystemTrayIcon::setupSupportInfoHotkey()
{
	s_supportInfoTrayIcon = this;

#ifdef Q_OS_WIN
	if( s_supportInfoHotkeyRegistered )
	{
		return;
	}

	if( RegisterHotKey( nullptr, SupportInfoHotkeyId, MOD_NOREPEAT, VK_F8 ) == FALSE )
	{
		vWarning() << "[support-info] could not register global F8 hotkey";
		return;
	}

	if( s_supportInfoHotkeyFilter == nullptr )
	{
		s_supportInfoHotkeyFilter = new SupportInfoHotkeyFilter();
		qApp->installNativeEventFilter( s_supportInfoHotkeyFilter );
	}

	s_supportInfoHotkeyRegistered = true;
	vInfo() << "[support-info] global F8 hotkey registered";
#else
	static bool shortcutInstalled = false;
	if( shortcutInstalled )
	{
		return;
	}

	auto* shortcut = new QShortcut( QKeySequence( Qt::Key_F8 ), qApp );
	shortcut->setContext( Qt::ApplicationShortcut );
	QObject::connect( shortcut, &QShortcut::activated, this, &SystemTrayIcon::showSupportInfoDialog );
	shortcutInstalled = true;
#endif
}



