bool isLoopbackClientAddress( const QString& ip )
{
	return ip == QLatin1String( "127.0.0.1" ) ||
		   ip == QLatin1String( "::1" ) ||
		   ip == QLatin1String( "0:0:0:0:0:0:0:1" );
}

QString firstNonLoopbackIpv4()
{
	const auto addresses = QNetworkInterface::allAddresses();
	for( const auto& addr : addresses )
	{
		if( addr.protocol() == QAbstractSocket::IPv4Protocol && !addr.isLoopback() )
		{
			return addr.toString();
		}
	}

	return {};
}

QString normalizeIpAddress( const QString& ipAddress )
{
	static const auto ipv4MappedPrefix = QStringLiteral("::ffff:");
	if( ipAddress.startsWith( ipv4MappedPrefix, Qt::CaseInsensitive ) )
	{
		return ipAddress.mid( ipv4MappedPrefix.size() );
	}

	return ipAddress;
}

QString resolvedHostName( const QString& ipAddress )
{
	const auto normalizedIpAddress = normalizeIpAddress( ipAddress );
	const auto hostInfo = QHostInfo::fromName( normalizedIpAddress );
	if( hostInfo.error() == QHostInfo::NoError && !hostInfo.hostName().isEmpty() )
	{
		return hostInfo.hostName();
	}

	return normalizedIpAddress;
}

QString formatElapsedTime( qint64 elapsedMilliseconds )
{
	const auto totalSeconds = qMax<qint64>( 0, elapsedMilliseconds / 1000 );
	const auto hours = totalSeconds / 3600;
	const auto minutes = (totalSeconds % 3600) / 60;
	const auto seconds = totalSeconds % 60;

	if( hours > 0 )
	{
		return QStringLiteral( "%1:%2:%3" )
				.arg( hours, 2, 10, QLatin1Char('0') )
				.arg( minutes, 2, 10, QLatin1Char('0') )
				.arg( seconds, 2, 10, QLatin1Char('0') );
	}

	return QStringLiteral( "%1:%2" )
			.arg( minutes, 2, 10, QLatin1Char('0') )
			.arg( seconds, 2, 10, QLatin1Char('0') );
}

QString trayErrorMessageForAuthFailure( VncServerClient* client )
{
	switch( client->authFailureReason() )
	{
	case VncServerClient::AuthFailureReason::Password:
		return QStringLiteral( "Estado: Senha incorreta" );
	case VncServerClient::AuthFailureReason::Login:
		return QStringLiteral( "Estado: Erro de login" );
	case VncServerClient::AuthFailureReason::Connection:
	default:
		return QStringLiteral( "Estado: Erro de conexao" );
	}
}

