ComputerControlServer::ComputerControlServer( QObject* parent ) :
	VeyonServerInterface(parent),
	m_allowedIPs(),
	m_failedAuthHosts(),
	m_featureWorkerManager( *this ),
	m_serverAuthenticationManager( this ),
	m_serverAccessControlManager( m_featureWorkerManager, VeyonCore::builtinFeatures().desktopAccessDialog(), this ),
	m_vncServer(),
	m_vncProxyServer( VeyonCore::config().localConnectOnly() || VeyonCore::builtinFeatures().accessControlProvider().isAccessToLocalComputerDenied() ?
						  QHostAddress::LocalHost : QHostAddress::Any,
					  VeyonCore::config().veyonServerPort() + VeyonCore::sessionId(),
					  this,
					  this )
{
	m_trayUpdateTimer.setInterval( 1000 );
	connect( &m_trayUpdateTimer, &QTimer::timeout, this, &ComputerControlServer::updateTrayIconToolTip );

	updateTrayIconToolTip();

	// make app terminate once the VNC server thread has finished
	connect( &m_vncServer, &VncServer::finished, QCoreApplication::instance(), &QCoreApplication::quit );

	connect( &m_serverAuthenticationManager, &ServerAuthenticationManager::finished,
			 this, &ComputerControlServer::showAuthenticationMessage );

	connect( &m_serverAccessControlManager, &ServerAccessControlManager::finished,
			 this, &ComputerControlServer::showAccessControlMessage );

	connect(&m_vncProxyServer, &VncProxyServer::serverMessageProcessed,
			 this, &ComputerControlServer::sendAsyncFeatureMessages, Qt::DirectConnection);
	connect(&m_vncProxyServer, &VncProxyServer::serverMessageProcessed,
			 this, &ComputerControlServer::updateTrayIconToolTip, Qt::DirectConnection);
	connect( &m_vncProxyServer, &VncProxyServer::connectionClosed, this, &ComputerControlServer::handleProxyConnectionClosed );

	m_localTrayServer = new QLocalServer( this );
	QLocalServer::removeServer( SystemTrayIcon::localTrayServerName() );
	if( m_localTrayServer->listen( SystemTrayIcon::localTrayServerName() ) )
	{
		connect( m_localTrayServer, &QLocalServer::newConnection, this, &ComputerControlServer::handleLocalTrayNotification );
	}
	else
	{
		vWarning() << "[tray][local-notify] could not listen on" << SystemTrayIcon::localTrayServerName();
	}
}



ComputerControlServer::~ComputerControlServer()
{
	vDebug();

	m_vncProxyServer.stop();
}



bool ComputerControlServer::start()
{
	AccessLogWriter::startTamperedLogProtection( m_featureWorkerManager, this );
	AccessLogWriter::validateAccessLogsOnStartup();
	AccessLogWriter::scheduleDailyAccessLogValidation( this );
	VeyonCore::builtinFeatures().systemTrayIcon().ensureSessionWorker( m_featureWorkerManager );

	if( m_vncProxyServer.start( m_vncServer.serverPort(), m_vncServer.password() ) == false )
	{
		return false;
	}

	m_vncServer.prepare();
	m_vncServer.start();

	CimedVersionAlertMonitor::startOnSentinelHosts( m_featureWorkerManager, this );

	return true;
}



VncProxyConnection* ComputerControlServer::createVncProxyConnection( QTcpSocket* clientSocket,
																	 int vncServerPort,
																	 const Password& vncServerPassword,
																	 QObject* parent )
{
	auto client = new ComputerControlClient( this, clientSocket, vncServerPort, vncServerPassword, parent );

	// #region debug-point P:create-proxy-client
	vWarning() << "[DEBUG][tray-runtime-state] createVncProxyConnection"
			   << "peer" << clientSocket->peerAddress().toString()
			   << "port" << clientSocket->peerPort();
	// #endregion

	const auto peerIp = normalizeIpAddress( clientSocket->peerAddress().toString() );
	if( isLoopbackClientAddress( peerIp ) == false )
	{
		setTrayState( TrayConnectionState::Connecting, client->serverClient() );
	}

	connect( client, &ComputerControlClient::serverConnectionClosed, this,
		[=, this]() { checkForIncompleteAuthentication(client->serverClient()); },
		Qt::DirectConnection );

	return client;
}



bool ComputerControlServer::handleFeatureMessage(ComputerControlClient* client)
{
	auto socket = client->proxyClientSocket();

	char messageType;
	if( socket->getChar( &messageType ) == false )
	{
		vWarning() << "could not read feature message!";
		return false;
	}

	// receive message
	FeatureMessage featureMessage;
	if( featureMessage.isReadyForReceive( socket ) == false )
	{
		socket->ungetChar( messageType );
		return false;
	}

	if (featureMessage.receive(socket) == false)
	{
		return false;
	}

	VeyonCore::featureManager().handleFeatureMessage( *this, MessageContext{socket, client}, featureMessage );

	return true;
}



bool ComputerControlServer::sendFeatureMessageReply( const MessageContext& context, const FeatureMessage& reply )
{
	vDebug() << reply;

	if (context.ioDevice())
	{
		return reply.sendAsRfbMessage(context.ioDevice());
	}

	return false;
}



void ComputerControlServer::setMinimumFramebufferUpdateInterval(const MessageContext& context, int interval)
{
	auto client = qobject_cast<ComputerControlClient *>(context.connection());
	if (client)
	{
		client->setMinimumFramebufferUpdateInterval(interval);
	}
}



void ComputerControlServer::checkForIncompleteAuthentication( VncServerClient* client )
{
	// connection to client closed during authentication?
	if( client->protocolState() == VncServerProtocol::State::AuthenticationTypes ||
		client->protocolState() == VncServerProtocol::State::Authenticating )
	{
		// then mark as failed authentication and report it
		client->setAuthFailureReason( VncServerClient::AuthFailureReason::Connection );
		client->setAuthState( VncServerClient::AuthState::Failed );

		showAuthenticationMessage( client );
	}
}

void ComputerControlServer::showAuthenticationMessage( VncServerClient* client )
{
	// #region debug-point Q:auth-finished
	vWarning() << "[DEBUG][tray-runtime-state] showAuthenticationMessage"
			   << "authState" << static_cast<int>( client->authState() )
			   << "protocolState" << static_cast<int>( client->protocolState() )
			   << "host" << client->hostAddress()
			   << "user" << client->username();
	// #endregion

	if( client->authState() == VncServerClient::AuthState::Successful )
	{
		setTrayState( TrayConnectionState::Authenticating, client );
		return;
	}

	if( client->authState() == VncServerClient::AuthState::Failed )
	{
		setTrayState( TrayConnectionState::Error, client, trayErrorMessageForAuthFailure( client ) );

		vWarning() << "Authentication failed for" << client->hostAddress() << client->username();

		if (VeyonCore::config().failedAuthenticationNotificationsEnabled() &&
			VeyonCore::platform().sessionFunctions().currentSessionHasUser())
		{
			QMutexLocker l( &m_dataMutex );

			if( m_failedAuthHosts.contains( client->hostAddress() ) == false )
			{
				m_failedAuthHosts += client->hostAddress();

				const auto fqdn = HostAddress( client->hostAddress() ).tryConvert( HostAddress::Type::FullyQualifiedDomainName );

				VeyonCore::builtinFeatures().systemTrayIcon().showMessage(
							tr( "Authentication error" ),
							tr( "User \"%1\" at host \"%2\" attempted to access this computer "
								"but could not authenticate successfully." ).arg( client->username(), fqdn ),
							m_featureWorkerManager );
			}
		}
	}
}



void ComputerControlServer::showAccessControlMessage( VncServerClient* client )
{
	// #region debug-point R:access-finished
	vWarning() << "[DEBUG][tray-runtime-state] showAccessControlMessage"
			   << "accessState" << static_cast<int>( client->accessControlState() )
			   << "protocolState" << static_cast<int>( client->protocolState() )
			   << "host" << client->hostAddress()
			   << "user" << client->username();
	// #endregion

	if( client->accessControlState() == VncServerClient::AccessControlState::Successful &&
		client->protocolState() == VncServerProtocol::State::AccessControl )
	{
		vInfo() << "Access control successful for" << client->hostAddress() << client->username();

		setTrayState( TrayConnectionState::Connected, client );

		if (VeyonCore::config().remoteConnectionNotificationsEnabled() &&
			VeyonCore::platform().sessionFunctions().currentSessionHasUser())
		{
			const auto fqdn = HostAddress( client->hostAddress() ).tryConvert( HostAddress::Type::FullyQualifiedDomainName );

			VeyonCore::builtinFeatures().systemTrayIcon().showMessage(
						tr( "Remote access" ),
						tr( "User \"%1\" at host \"%2\" is now accessing this computer." ).
						arg( client->username(), fqdn ),
						m_featureWorkerManager );
		}

	}
	else if( client->accessControlState() == VncServerClient::AccessControlState::Failed )
	{
		vWarning() << "Access control failed for" << client->hostAddress() << client->username();

		setTrayState( TrayConnectionState::Error, client, QStringLiteral( "Estado: Erro de conexao" ) );

		if( VeyonCore::config().failedAuthenticationNotificationsEnabled() )
		{
			QMutexLocker l( &m_dataMutex );

			if( m_failedAccessControlHosts.contains( client->hostAddress() ) == false )
			{
				m_failedAccessControlHosts += client->hostAddress();

				const auto fqdn = HostAddress( client->hostAddress() ).tryConvert( HostAddress::Type::FullyQualifiedDomainName );

				VeyonCore::builtinFeatures().systemTrayIcon().showMessage(
							tr( "Access control error" ),
							tr( "User \"%1\" at host \"%2\" attempted to access this computer "
								"but has been blocked due to access control settings." ).
							arg( client->username(), fqdn ),
							m_featureWorkerManager );
			}
		}
	}
}



QFutureWatcher<void>* ComputerControlServer::resolveFQDNs( const QStringList& hosts )
{
	auto watcher = new QFutureWatcher<void>();

	watcher->setFuture( QtConcurrent::run( [this, hosts]() {
		for( const auto& host : hosts )
		{
			const auto fqdn = HostAddress( host ).tryConvert( HostAddress::Type::FullyQualifiedDomainName );

			m_dataMutex.lock();
			m_resolvedHostNames[host] = fqdn;
			m_dataMutex.unlock();
		}
	} ) );

	connect( watcher, &QFutureWatcher<void>::finished, watcher, &QObject::deleteLater );

	return watcher;
}



void ComputerControlServer::sendAsyncFeatureMessages(VncProxyConnection* connection)
{
	VeyonCore::featureManager().sendAsyncFeatureMessages(*this, MessageContext{connection->proxyClientSocket()});
}



void ComputerControlServer::setTrayState( TrayConnectionState state, VncServerClient* client, const QString& errorMessage )
{
	if( client )
	{
		const auto clientIp = normalizeIpAddress( client->hostAddress() );
		if( isLoopbackClientAddress( clientIp ) )
		{
			return;
		}
	}

	// #region debug-point A:tray-state-transition
	vDebug() << "[DEBUG][tray-runtime-state] setTrayState"
			 << "state" << static_cast<int>( state )
			 << "client" << ( client ? client->hostAddress() : QStringLiteral("<null>") )
			 << "user" << ( client ? client->username() : QStringLiteral("<null>") )
			 << "errorMessage" << errorMessage;
	// #endregion
	m_trayState = state;

	if( state == TrayConnectionState::Error )
	{
		m_trayErrorMessage = errorMessage.isEmpty() ? QStringLiteral( "Estado: Erro de conexao" ) : errorMessage;
	}
	else
	{
		m_trayErrorMessage.clear();
	}

	if( client )
	{
		m_trayClientUser = client->username();
		m_trayOriginIp = normalizeIpAddress( client->hostAddress() );
		m_trayOriginHost = m_trayOriginIp.isEmpty() ? QString{} : resolvedHostName( m_trayOriginIp );
		m_trayDestinationHost = QHostInfo::localHostName();
		m_trayDestinationIp = normalizeIpAddress( firstNonLoopbackIpv4() );
	}

	if( state == TrayConnectionState::Connected )
	{
		m_trayConnectionTimer.restart();
		m_trayUpdateTimer.start();
	}
	else if( state == TrayConnectionState::Idle || state == TrayConnectionState::Error )
	{
		m_trayUpdateTimer.stop();
	}

	updateTrayIconToolTip();
}



void ComputerControlServer::clearTraySession()
{
	m_trayClientUser.clear();
	m_trayOriginHost.clear();
	m_trayOriginIp.clear();
	m_trayDestinationHost.clear();
	m_trayDestinationIp.clear();
	m_trayErrorMessage.clear();
	m_trayUpdateTimer.stop();
}



bool ComputerControlServer::hasInboundTrayClients() const
{
	for( const auto* client : m_vncProxyServer.clients() )
	{
		if( client == nullptr || client->proxyClientSocket() == nullptr )
		{
			continue;
		}

		const auto clientIp = normalizeIpAddress( client->proxyClientSocket()->peerAddress().toString() );
		if( isLoopbackClientAddress( clientIp ) == false )
		{
			return true;
		}
	}

	return false;
}



void ComputerControlServer::scheduleTrayErrorReset( int resetAfterMs )
{
	QTimer::singleShot( resetAfterMs, this, [this]() {
		if( m_trayState != TrayConnectionState::Error || hasInboundTrayClients() )
		{
			return;
		}

		clearTraySession();
		m_trayState = TrayConnectionState::Idle;
		updateTrayIconToolTip();
	} );
}



void ComputerControlServer::handleLocalTrayNotification()
{
	while( m_localTrayServer && m_localTrayServer->hasPendingConnections() )
	{
		QLocalSocket* socket = m_localTrayServer->nextPendingConnection();
		if( socket == nullptr )
		{
			continue;
		}

		if( socket->waitForReadyRead( 500 ) )
		{
			QDataStream stream( socket );
			stream.setVersion( QDataStream::Qt_6_0 );

			quint32 magic = 0;
			qint32 statusValue = static_cast<qint32>( SystemTrayIcon::StatusIndicator::Error );
			QString toolTip = QStringLiteral( "Estado: Erro de conexao" );
			qint32 resetAfterMs = 8000;

			stream >> magic >> statusValue >> toolTip >> resetAfterMs;

			if( magic == quint32( 0x56545931 ) )
			{
				const auto status = static_cast<SystemTrayIcon::StatusIndicator>( statusValue );
				const auto trayMessage = toolTip.isEmpty() ? QStringLiteral( "Estado: Erro de conexao" ) : toolTip;

				if( status == SystemTrayIcon::StatusIndicator::Error )
				{
					setTrayState( TrayConnectionState::Error, nullptr, trayMessage );
					scheduleTrayErrorReset( resetAfterMs );
				}
				else if( status == SystemTrayIcon::StatusIndicator::Connected )
				{
					m_trayOutboundSession = true;
					m_trayState = TrayConnectionState::Connected;
					m_trayConnectionTimer.restart();
					m_trayUpdateTimer.start();
					VeyonCore::builtinFeatures().systemTrayIcon().setStatusIndicator( status, m_featureWorkerManager );
					VeyonCore::builtinFeatures().systemTrayIcon().setToolTip( trayMessage, m_featureWorkerManager );
				}
				else if( status == SystemTrayIcon::StatusIndicator::Idle )
				{
					m_trayOutboundSession = false;
					clearTraySession();
					m_trayState = TrayConnectionState::Idle;
					updateTrayIconToolTip();
				}

				vWarning() << "[DEBUG][tray-local-notify] applied"
						   << "status" << statusValue
						   << "tooltip" << trayMessage
						   << "resetMs" << resetAfterMs;
			}
		}

		socket->disconnectFromServer();
		socket->deleteLater();
	}
}



void ComputerControlServer::handleProxyConnectionClosed( VncProxyConnection* connection )
{
	Q_UNUSED( connection )

	m_vncProxyServer.closeStaleConnections();

	// #region debug-point B:proxy-closed
	vDebug() << "[DEBUG][tray-runtime-state] handleProxyConnectionClosed"
			 << "activeClients" << m_vncProxyServer.clients().size()
			 << "trayStateBefore" << static_cast<int>( m_trayState );
	// #endregion

	if( hasInboundTrayClients() == false )
	{
		if( m_trayState == TrayConnectionState::Error )
		{
			scheduleTrayErrorReset();
		}
		else if( m_trayOutboundSession == false && m_trayState != TrayConnectionState::Idle )
		{
			clearTraySession();
			m_trayState = TrayConnectionState::Idle;
		}
	}
	else if( m_trayState == TrayConnectionState::Connected )
	{
		m_trayUpdateTimer.start();
	}

	updateTrayIconToolTip();
}



void ComputerControlServer::updateTrayIconToolTip()
{
	if( m_trayState == TrayConnectionState::Connected && m_trayOutboundSession == false )
	{
		m_vncProxyServer.closeStaleConnections();
		if( hasInboundTrayClients() == false )
		{
			clearTraySession();
			m_trayState = TrayConnectionState::Idle;
		}
	}

	QMutexLocker locker( &m_dataMutex );
	// #region debug-point C:update-tooltip-entry
	vDebug() << "[DEBUG][tray-runtime-state] updateTrayIconToolTip"
			 << "trayState" << static_cast<int>( m_trayState )
			 << "proxyClients" << m_vncProxyServer.clients().size()
			 << "user" << m_trayClientUser
			 << "originIp" << m_trayOriginIp
			 << "destinationIp" << m_trayDestinationIp;
	// #endregion

	QStringList clients;
	QStringList hostsToResolve;
	clients.reserve( m_vncProxyServer.clients().size() );
	hostsToResolve.reserve( m_vncProxyServer.clients().size() );

	for( const auto* client : m_vncProxyServer.clients() )
	{
		const auto clientIpAddress = normalizeIpAddress( client->proxyClientSocket()->peerAddress().toString() );
		if( m_resolvedHostNames.contains( clientIpAddress ) == false )
		{
			hostsToResolve.append( clientIpAddress );
			clients.append( clientIpAddress );
		}
		else
		{
			clients.append( m_resolvedHostNames[clientIpAddress] );
		}
	}

	if( hostsToResolve.isEmpty() == false )
	{
		auto watcher = resolveFQDNs( hostsToResolve );
		connect( watcher, &QFutureWatcher<void>::finished, this, &ComputerControlServer::updateTrayIconToolTip );
	}

	auto trayStatus = SystemTrayIcon::StatusIndicator::Idle;
	QString toolTip;

	switch( m_trayState )
	{
	case TrayConnectionState::Connected:
		trayStatus = SystemTrayIcon::StatusIndicator::Connected;
		toolTip = QStringLiteral( "Estado: Monitorando\nCliente: %1\nTempo: %2\n%3 [%4]\n%5 [%6]" )
				.arg( m_trayClientUser.isEmpty() ? QStringLiteral("Desconhecido") : m_trayClientUser,
					  formatElapsedTime( m_trayConnectionTimer.isValid() ? m_trayConnectionTimer.elapsed() : 0 ),
					  m_trayOriginHost.isEmpty() ? QStringLiteral("Desconhecido") : m_trayOriginHost,
					  m_trayOriginIp.isEmpty() ? QStringLiteral("-") : m_trayOriginIp,
					  m_trayDestinationHost.isEmpty() ? QStringLiteral("Desconhecido") : m_trayDestinationHost,
					  m_trayDestinationIp.isEmpty() ? QStringLiteral("-") : m_trayDestinationIp );
		break;

	case TrayConnectionState::Authenticating:
		trayStatus = SystemTrayIcon::StatusIndicator::Authenticating;
		toolTip = QStringLiteral( "Estado: Autenticando" );
		break;

	case TrayConnectionState::Connecting:
		trayStatus = SystemTrayIcon::StatusIndicator::Connecting;
		toolTip = QStringLiteral( "Estado: Conectando" );
		break;

	case TrayConnectionState::Error:
		trayStatus = SystemTrayIcon::StatusIndicator::Error;
		toolTip = m_trayErrorMessage.isEmpty() ? QStringLiteral( "Estado: Erro de conexao" ) : m_trayErrorMessage;
		break;

	case TrayConnectionState::Idle:
	default:
		trayStatus = SystemTrayIcon::StatusIndicator::Idle;
		toolTip = ComputerSupportInfo::idleTrayHoverText();
		break;
	}

	// debug-point tray-state-sent
	vDebug() << "[tray][server] sending status"
			 << static_cast<int>( trayStatus )
			 << "tooltip"
			 << toolTip;
	// #region debug-point tray-tooltip-payload
	vWarning() << "[DEBUG][tray-tooltip-payload]"
			   << "trayState" << static_cast<int>( m_trayState )
			   << "trayStatus" << static_cast<int>( trayStatus )
			   << "tooltip" << toolTip;
	// #endregion
	// #region debug-point D:tray-message-sent
	vDebug() << "[DEBUG][tray-runtime-state] sending tray message"
			 << "status" << static_cast<int>( trayStatus )
			 << "tooltip" << toolTip;
	// #endregion
	VeyonCore::builtinFeatures().systemTrayIcon().setStatusIndicator( trayStatus, m_featureWorkerManager );
	VeyonCore::builtinFeatures().systemTrayIcon().setToolTip( toolTip, m_featureWorkerManager );
}

