QString primeiroIpv4Local()
{
	const auto addresses = QNetworkInterface::allAddresses();
	for( const auto& addr : addresses )
	{
		if( addr.protocol() == QAbstractSocket::IPv4Protocol && addr.isLoopback() == false )
		{
			return addr.toString();
		}
	}

	return {};
}

QString nomeHostPorEndereco( const QString& endereco )
{
	if( endereco.isEmpty() )
	{
		return {};
	}

	const auto hostInfo = QHostInfo::fromName( endereco );
	if( hostInfo.error() == QHostInfo::NoError && hostInfo.hostName().isEmpty() == false )
	{
		return hostInfo.hostName();
	}

	return endereco;
}

QString ipPorHost( const QString& host )
{
	const auto endereco = QHostAddress( host );
	if( endereco.isNull() == false && endereco.protocol() == QAbstractSocket::IPv4Protocol )
	{
		return endereco.toString();
	}

	const auto hostInfo = QHostInfo::fromName( host );
	for( const auto& addr : hostInfo.addresses() )
	{
		if( addr.protocol() == QAbstractSocket::IPv4Protocol && addr.isLoopback() == false )
		{
			return addr.toString();
		}
	}

	return host;
}

QString outboundDestinationName( const ComputerControlInterface::Pointer& computerControlInterface )
{
	const auto hostDestinoInformado = computerControlInterface->computer().hostName();
	const auto ipDestino = ipPorHost( hostDestinoInformado );
	auto nomeDestino = computerControlInterface->computerName();
	if( nomeDestino.isEmpty() || nomeDestino == hostDestinoInformado || nomeDestino == ipDestino )
	{
		nomeDestino = nomeHostPorEndereco( ipDestino );
	}
	if( nomeDestino.isEmpty() )
	{
		nomeDestino = hostDestinoInformado;
	}
	return nomeDestino;
}

QString outboundDestinationIp( const ComputerControlInterface::Pointer& computerControlInterface )
{
	return ipPorHost( computerControlInterface->computer().hostName() );
}

QString outboundTrayToolTip( const ComputerControlInterface::Pointer& computerControlInterface )
{
	QString usuario = qEnvironmentVariable( "USERNAME" );
	if( usuario.isEmpty() )
	{
		usuario = QStringLiteral( "desconhecido" );
	}

	const auto nomeDestino = outboundDestinationName( computerControlInterface );
	const auto ipDestino = outboundDestinationIp( computerControlInterface );

	return QStringLiteral( "Estado: Monitorando\nCliente: %1\nTempo: 00:00\n%2 [%3]\n%4 [%5]" )
			.arg( usuario,
				  QHostInfo::localHostName(),
				  primeiroIpv4Local(),
				  nomeDestino,
				  ipDestino );
}

void notifyOutboundTrayConnected( const ComputerControlInterface::Pointer& computerControlInterface )
{
	SystemTrayIcon::notifyLocalSessionTray( SystemTrayIcon::StatusIndicator::Connected,
											outboundTrayToolTip( computerControlInterface ),
											0 );
}

void notifyOutboundTrayIdle()
{
	SystemTrayIcon::notifyLocalSessionTray( SystemTrayIcon::StatusIndicator::Idle,
											ComputerSupportInfo::idleTrayHoverText(),
											0 );
}

void finalizeOutboundSession( const ComputerControlInterface::Pointer& computerControlInterface, qint64 elapsedMs )
{
	AccessLogRecorder::logOutboundDisconnect( outboundDestinationName( computerControlInterface ),
											outboundDestinationIp( computerControlInterface ),
											elapsedMs );
	notifyOutboundTrayIdle();
}

void notifyLocalTrayForConnectionState( VncConnection::State state )
{
	QString toolTip;

	switch( state )
	{
	case VncConnection::State::AuthenticationFailed:
		toolTip = QStringLiteral( "Estado: Senha incorreta" );
		break;
	case VncConnection::State::AccessControlFailed:
		toolTip = QStringLiteral( "Estado: Erro de conexao" );
		break;
	case VncConnection::State::ConnectionFailed:
	case VncConnection::State::ServerNotRunning:
	case VncConnection::State::HostOffline:
	case VncConnection::State::HostNameResolutionFailed:
		toolTip = QStringLiteral( "Estado: Erro de conexao" );
		break;
	default:
		return;
	}

	SystemTrayIcon::notifyLocalSessionTray( SystemTrayIcon::StatusIndicator::Error, toolTip );
}

