# Empacota Veyon_Custom em instalador NSIS (modelo oficial veyon.io)
param(
    [ValidateSet("win64", "win32", "both", "win64-dual", "win64-posto")]
    [string]$Architecture = "win64",
    [ValidateSet("lab", "posto", "both")]
    [string]$DefaultProfile = "lab"
)

$ErrorActionPreference = "Stop"

if ($Architecture -eq "win64-posto") {
    $Architecture = "win64"
    $DefaultProfile = "posto"
}
if ($Architecture -eq "win64-dual") {
    $DefaultProfile = "both"
}

$win64Variants = @(
    @{ Profile = "lab";   SetupName = "Veyon-CIMED-1.0-win64-setup.exe";       Label = "Laboratorio (Master ON, Interception OFF)" },
    @{ Profile = "posto"; SetupName = "Veyon-CIMED-1.0-win64-posto-setup.exe"; Label = "Posto (Master OFF, Interception OFF)" }
)

$Root = Split-Path -Parent (Split-Path -Parent $MyInvocation.MyCommand.Path)
$InstallerDir = Join-Path $Root "installer"
$Dist = Join-Path $Root "dist"
$Nsi = Join-Path $InstallerDir "veyon-cimed.nsi"
$Sanitize = Join-Path $Root "scripts\sanitize_veyon_custom.ps1"

$archMap = @{
    win64 = @{
        Source     = Join-Path $Root "Veyon_Custom"
        Payload    = Join-Path $InstallerDir "payload-win64"
        SetupName  = "Veyon-CIMED-1.0-win64-setup.exe"
        NsisDefine = "win64"
    }
    win32 = @{
        Source     = Join-Path $Root "Veyon_Custom_win32"
        Payload    = Join-Path $InstallerDir "payload-win32"
        SetupName  = "Veyon-CIMED-1.0-win32-setup.exe"
        NsisDefine = "win32"
    }
}

function Prepare-Payload {
    param(
        [string]$Source,
        [string]$Payload
    )

    if (-not (Test-Path $Source)) {
        throw "Pasta nao encontrada: $Source"
    }

    Write-Host "Preparando payload (estrutura oficial, logs locais vazios): $Source"
    if (Test-Path $Payload) { Remove-Item $Payload -Recurse -Force }
    New-Item -ItemType Directory -Path $Payload -Force | Out-Null

    $excludeDirs = @("_archive", "_deploy", "_deploy_logs_network_only", "Logs", "alertas_versao_incompativel")
    $excludeFiles = @(
        "acessos_integrity_state.txt",
        "acessos_veyon.log",
        "acessos_veyon_ad.log"
    )

    Get-ChildItem $Source -Force | ForEach-Object {
        if ($_.PSIsContainer -and $excludeDirs -contains $_.Name) {
            return
        }
        if ($_.PSIsContainer -and ($_.Name -eq "logs" -or $_.Name -eq "Logs")) {
            return
        }
        if (-not $_.PSIsContainer -and $excludeFiles -contains $_.Name) {
            return
        }
        if (-not $_.PSIsContainer -and $_.Name -match '\.bak') {
            return
        }
        Copy-Item $_.FullName $Payload -Recurse -Force
    }

    Get-ChildItem $Payload -Recurse -Directory -Force -ErrorAction SilentlyContinue |
        Where-Object { $_.Name -eq "_archive" } |
        ForEach-Object { Remove-Item $_.FullName -Recurse -Force }

    foreach ($logSub in @("acessos_veyon", "acessos_veyon_ad")) {
        $logDir = Join-Path $Payload "logs\$logSub"
        New-Item -ItemType Directory -Path $logDir -Force | Out-Null
    }

    $leaked = Get-ChildItem $Payload -Recurse -Force -ErrorAction SilentlyContinue |
        Where-Object {
            $_.Name -eq "acessos_integrity_state.txt" -or
            $_.Name -match '\.bak' -or
            $_.Name -match '\.log$' -or
            $_.FullName -match '\\_archive\\' -or
            $_.FullName -match '\\_deploy\\' -or
            $_.FullName -match '\\_deploy_logs_network_only' -or
            $_.FullName -match '\\alertas_versao_incompativel\\' -or
            $_.FullName -match 'versao_incompativel\.log$'
        }
    if ($leaked) {
        $leaked | ForEach-Object { Write-Host "ERRO: runtime no payload: $($_.FullName)" }
        throw "Payload contem arquivos de runtime (logs, integrity state ou _archive)."
    }
}

function Build-InstallerNsis {
    param(
        [string]$NsisDefine,
        [string]$PayloadDir,
        [string]$SetupName,
        [string]$DefaultProf = "lab"
    )

    $payloadLeaf = Split-Path $PayloadDir -Leaf
    Write-Host "Compilando $SetupName (padrao: $DefaultProf)..." -ForegroundColor Cyan
    if ($DefaultProf -eq "lab") {
        Write-Host "  AD: $SetupName /S" -ForegroundColor DarkGray
    } else {
        Write-Host "  AD: $SetupName /S" -ForegroundColor DarkGray
    }
    Push-Location $InstallerDir
    & $script:makensis "/V2" `
        "/DVEYON_ARCH=$NsisDefine" `
        "/DINSTALL_DEFAULT=$DefaultProf" `
        "/DINSTALLER_NAME=$SetupName" `
        "/DPAYLOAD_DIR=$payloadLeaf" `
        $Nsi
    if ($LASTEXITCODE -ne 0) { throw "makensis falhou ($SetupName) codigo $LASTEXITCODE" }
    Pop-Location

    $setup = Join-Path $Dist $SetupName
    if (-not (Test-Path $setup)) { throw "Instalador nao gerado: $setup" }

    $downloads = Join-Path $env:USERPROFILE "Downloads\$SetupName"
    Copy-Item $setup $downloads -Force

    Write-Host "OK -> $setup" -ForegroundColor Green
    Write-Host "Copia -> $downloads"
    Get-Item $setup | Select-Object FullName, Length, LastWriteTime
}

$makensis = @(
    "${env:ProgramFiles(x86)}\NSIS\makensis.exe",
    "${env:ProgramFiles}\NSIS\makensis.exe"
) | Where-Object { Test-Path $_ } | Select-Object -First 1

if (-not $makensis) {
    throw "NSIS (makensis.exe) nao encontrado. Instale: winget install NSIS.NSIS"
}

New-Item -ItemType Directory -Path $Dist -Force | Out-Null

if ($DefaultProfile -eq "both" -or $Architecture -eq "win64-dual") {
    $cfg = $archMap["win64"]
    if ((Test-Path $Sanitize) -and ($cfg.Source)) {
        & $Sanitize -CustomDir $cfg.Source
    }
    Prepare-Payload -Source $cfg.Source -Payload $cfg.Payload
    foreach ($v in $win64Variants) {
        Write-Host "`n=== $($v.Label) ===" -ForegroundColor Yellow
        Build-InstallerNsis -NsisDefine "win64" -PayloadDir $cfg.Payload `
            -SetupName $v.SetupName -DefaultProf $v.Profile
    }
} else {
    $targets = if ($Architecture -eq "both") { @("win64", "win32") } else { @($Architecture) }
    foreach ($arch in $targets) {
        $cfg = $archMap[$arch]
        if ((Test-Path $Sanitize) -and ($arch -eq "win64")) {
            & $Sanitize -CustomDir $cfg.Source
        }
        Prepare-Payload -Source $cfg.Source -Payload $cfg.Payload
        $prof = if ($arch -eq "win64") { $DefaultProfile } else { "lab" }
        $setupName = if ($arch -eq "win64" -and $prof -eq "posto") {
            "Veyon-CIMED-1.0-win64-posto-setup.exe"
        } else {
            $cfg.SetupName
        }
        Build-InstallerNsis -NsisDefine $cfg.NsisDefine -PayloadDir $cfg.Payload `
            -SetupName $setupName -DefaultProf $prof
    }
}

