/*
 * CimedVersionCompatibility.cpp - inbound version compatibility checks
 */

#include "CimedVersionCompatibility.h"

#include <QAbstractSocket>
#include <QHostInfo>
#include <QNetworkInterface>

#include "AccessLogAdLookup_win.h"
