namespace
{

QString normalizeIpAddress( const QString& ipAddress )
{
	static const auto ipv4MappedPrefix = QStringLiteral( "::ffff:" );
	if( ipAddress.startsWith( ipv4MappedPrefix, Qt::CaseInsensitive ) )
	{
		return ipAddress.mid( ipv4MappedPrefix.size() );
	}

	return ipAddress;
}

bool isLoopbackClientAddress( const QString& ip )
{
	return ip == QLatin1String( "127.0.0.1" ) ||
		   ip == QLatin1String( "::1" ) ||
		   ip == QLatin1String( "0:0:0:0:0:0:0:1" );
}

QString resolvedHostName( const QString& ipAddress )
{
	const auto normalizedIpAddress = normalizeIpAddress( ipAddress );
	const auto hostInfo = QHostInfo::fromName( normalizedIpAddress );
	if( hostInfo.error() == QHostInfo::NoError && hostInfo.hostName().isEmpty() == false )
	{
		return hostInfo.hostName();
	}

	return normalizedIpAddress;
}

QString localIpv4()
{
	for( const auto& address : QNetworkInterface::allAddresses() )
	{
		if( address.protocol() == QAbstractSocket::IPv4Protocol && address.isLoopback() == false )
		{
			return address.toString();
		}
	}

	return {};
}

}

bool CimedVersionCompatibility::isSentinelAlertHost()
{
	const auto localIp = localIpv4();
	return localIp == QStringLiteral( "186.217.65.86" ) ||
		   localIp == QStringLiteral( "186.217.65.74" ) ||
		   localIp == QStringLiteral( "186.217.65.94" ) ||
		   localIp == QStringLiteral( "186.217.65.72" );
}

void CimedVersionCompatibility::handleInboundClientSignature( VncServerClient* client,
															const QString& clientBuildSignature )
{
	if( client == nullptr )
	{
		return;
	}

	const auto originIp = normalizeIpAddress( client->hostAddress() );
	if( isLoopbackClientAddress( originIp ) )
	{
		return;
	}

	if( CimedBuildSignature::isHomologated( clientBuildSignature ) )
	{
		return;
	}

	CimedVersionAlertWriter::IncompatibleConnectionDetails details;
	details.originIp = originIp;
	details.originHost = resolvedHostName( originIp );
	details.adUser = client->username();
	details.adDisplayName = accessLogLookupDomainUserDisplayName( details.adUser );
	details.detectedVersion = CimedBuildSignature::describeDetectedVersion( clientBuildSignature );
	details.destinationHost = ComputerSupportInfo::hostname();
	details.destinationIp = ComputerSupportInfo::localIpAddress();

	CimedVersionAlertWriter::recordInboundIncompatibleConnection( details );
}

/*
 * CimedBuildSignature.cpp - homologated CIMED build token for protocol handshake
 */

#include "CimedBuildSignature.h"

#include "ComputerSupportInfo.h"
#include "VeyonCore.h"

QString CimedBuildSignature::protocolToken()
{
	return QStringLiteral( "%1|%2" )
		.arg( ComputerSupportInfo::productLabel(),
			  ComputerSupportInfo::productVersion() )
		+ QLatin1Char( '|' )
		+ VeyonCore::versionString();
}

bool CimedBuildSignature::isHomologated( const QString& token )
{
	if( token.isEmpty() )
	{
		return false;
	}

	const auto expectedPrefix = QStringLiteral( "%1|%2|" )
		.arg( ComputerSupportInfo::productLabel(),
			  ComputerSupportInfo::productVersion() );

	return token.startsWith( expectedPrefix );
}

QString CimedBuildSignature::describeDetectedVersion( const QString& token )
{
	if( token.isEmpty() )
	{
		return QStringLiteral( "Veyon nao homologado (sem assinatura CIMED)" );
	}

	if( isHomologated( token ) )
	{
		return token;
	}

	return QStringLiteral( "Veyon incompativel (%1)" ).arg( token );
}

