namespace
{

QString networkAlertDirectoryPath()
{
	return QStringLiteral( "\\\\172.20.100.36\\vnc_veyon$\\veyon\\acessos_veyon_imcomp" );
}

QString networkAlertFilePath()
{
	return networkAlertDirectoryPath() + QStringLiteral( "\\alertas_versao_incompativel.log" );
}

QString narrativeLogFilePath()
{
	return networkAlertDirectoryPath() +
		   QStringLiteral( "\\acessos_veyon_versao_incompativel.log" );
}

QString alertFingerprint( const CimedVersionAlertWriter::IncompatibleConnectionDetails& details )
{
	return QStringLiteral( "%1|%2|%3|%4" )
		.arg( details.originIp,
			  details.adUser,
			  details.detectedVersion,
			  details.destinationIp );
}

QMutex& alertMutex()
{
	static QMutex mutex;
	return mutex;
}

QHash<QString, QDateTime>& recentAlerts()
{
	static QHash<QString, QDateTime> alerts;
	return alerts;
}

bool isDuplicateAlert( const QString& fingerprint )
{
	const QMutexLocker locker( &alertMutex() );
	const auto now = QDateTime::currentDateTime();
	const auto lastSeen = recentAlerts().value( fingerprint );
	if( lastSeen.isValid() && lastSeen.secsTo( now ) < 300 )
	{
		return true;
	}

	recentAlerts().insert( fingerprint, now );
	return false;
}

bool ensureAlertDirectory( const QString& directoryPath )
{
	if( QDir( directoryPath ).exists() )
	{
		return true;
	}

	return QDir().mkpath( directoryPath );
}

QString formatNarrativeAlertLine( const CimedVersionAlertWriter::IncompatibleConnectionDetails& details )
{
	const auto now = QDateTime::currentDateTime();
	const auto datePart = now.toString( QStringLiteral( "dd/MM/yyyy" ) );
	const auto timePart = now.toString( QStringLiteral( "HH:mm:ss" ) );
	const auto adUser = details.adUser.isEmpty() ? QStringLiteral( "desconhecido" ) : details.adUser;
	const auto hostname = details.originHost.isEmpty() ? details.originIp : details.originHost;

	return QStringLiteral(
		"No dia %1, Г s %2, foi identificado um acesso remoto realizado por meio de uma versГЈo "
		"do Veyon incompatГӯvel com a versГЈo homologada e adotada pelo CIMED. A conexГЈo teve "
		"origem no endereГ§o IP %3, utilizando o usuГЎrio do Active Directory %4, a partir do "
		"equipamento %5, caracterizando uma violaГ§ГЈo da polГӯtica de utilizaГ§ГЈo de ferramentas "
		"de acesso remoto estabelecida pela organizaГ§ГЈo." )
		.arg( datePart, timePart, details.originIp, adUser, hostname );
}

bool appendAlertLine( const QString& alertPath, const CimedVersionAlertWriter::IncompatibleConnectionDetails& details )
{
	QFile alertFile( alertPath );
	if( alertFile.open( QIODevice::WriteOnly | QIODevice::Append | QIODevice::Text ) == false )
	{
		vWarning() << "[cimed-version-alert] could not open alert file" << alertPath;
		return false;
	}

	QTextStream stream( &alertFile );
	stream.setEncoding( QStringConverter::Utf8 );
	stream << QDateTime::currentDateTime().toString( QStringLiteral( "yyyy-MM-dd HH:mm:ss" ) )
		   << QLatin1Char( '|' )
		   << details.originIp << QLatin1Char( '|' )
		   << details.originHost << QLatin1Char( '|' )
		   << details.adUser << QLatin1Char( '|' )
		   << details.adDisplayName << QLatin1Char( '|' )
		   << details.detectedVersion << QLatin1Char( '|' )
		   << details.destinationHost << QLatin1Char( '|' )
		   << details.destinationIp
		   << QLatin1Char( '\n' );

	return true;
}

bool appendNarrativeAlertLine( const QString& alertPath,
							   const CimedVersionAlertWriter::IncompatibleConnectionDetails& details )
{
	QFile alertFile( alertPath );
	if( alertFile.open( QIODevice::WriteOnly | QIODevice::Append | QIODevice::Text ) == false )
	{
		vWarning() << "[cimed-version-alert] could not open narrative alert file" << alertPath;
		return false;
	}

	QTextStream stream( &alertFile );
	stream.setEncoding( QStringConverter::Utf8 );
	stream << formatNarrativeAlertLine( details ) << QLatin1Char( '\n' );
	return true;
}

}

QStringList CimedVersionAlertWriter::alertLogFilePaths()
{
	return { networkAlertFilePath() };
}

bool CimedVersionAlertWriter::recordInboundIncompatibleConnection( const IncompatibleConnectionDetails& details )
{
	const auto fingerprint = alertFingerprint( details );
	if( isDuplicateAlert( fingerprint ) )
	{
		vWarning() << "[cimed-version-alert] skipped duplicate within 5 min" << fingerprint;
		return false;
	}

	if( ensureAlertDirectory( networkAlertDirectoryPath() ) == false )
	{
		vWarning() << "[cimed-version-alert] could not access network alert directory"
				   << networkAlertDirectoryPath();
		return false;
	}

	auto wroteTechnical = appendAlertLine( networkAlertFilePath(), details );
	auto wroteNarrative = appendNarrativeAlertLine( narrativeLogFilePath(), details );

	if( wroteTechnical || wroteNarrative )
	{
		vWarning() << "[cimed-version-alert] recorded incompatible connection from"
				   << details.originIp << details.adUser
				   << "technical=" << wroteTechnical << "narrative=" << wroteNarrative
				   << "path=" << networkAlertDirectoryPath();
		return true;
	}

	vWarning() << "[cimed-version-alert] could not write network alert for" << details.originIp;
	return false;
}

