CimedVersionAlertMonitor::CimedVersionAlertMonitor( FeatureWorkerManager& featureWorkerManager, QObject* parent ) :

	QObject( parent ),

	m_featureWorkerManager( featureWorkerManager )

{

	connect( &m_pollTimer, &QTimer::timeout, this, &CimedVersionAlertMonitor::pollAlertFiles );

	m_pollTimer.start( 2000 );

	pollAlertFiles();

}



void CimedVersionAlertMonitor::pollAlertFiles()

{

	for( const auto& alertPath : CimedVersionAlertWriter::alertLogFilePaths() )

	{

		pollAlertFile( alertPath );

	}

}



void CimedVersionAlertMonitor::pollAlertFile( const QString& alertPath )

{

	auto& fileState = m_fileStates[alertPath];



	QFile alertFile( alertPath );

	if( alertFile.exists() == false )

	{

		if( fileState.initialized == false )

		{

			fileState.initialized = true;

			fileState.lastFileSize = 0;

			vWarning() << "[cimed-version-alert] sentinel waiting for network alert file" << alertPath;

		}



		return;

	}



	if( alertFile.open( QIODevice::ReadOnly | QIODevice::Text ) == false )

	{

		vWarning() << "[cimed-version-alert] sentinel could not read alert file" << alertPath;

		return;

	}



	const auto fileSize = alertFile.size();

	if( fileSize < fileState.lastFileSize )

	{

		fileState.lastFileSize = 0;

	}



	if( fileState.initialized == false )

	{

		fileState.initialized = true;

		fileState.lastFileSize = fileSize;

		vWarning() << "[cimed-version-alert] sentinel seeded existing alert file"

				   << alertPath << "bytes" << fileSize;

		return;

	}



	if( fileSize <= fileState.lastFileSize )

	{

		return;

	}



	if( alertFile.seek( fileState.lastFileSize ) == false )

	{

		vWarning() << "[cimed-version-alert] sentinel could not seek alert file" << alertPath;

		return;

	}



	QTextStream stream( &alertFile );

	stream.setEncoding( QStringConverter::Utf8 );



	while( stream.atEnd() == false )

	{

		const auto line = stream.readLine().trimmed();

		if( line.isEmpty() )

		{

			continue;

		}



		const auto fingerprint = lineFingerprint( line );

		if( m_seenAlertFingerprints.contains( fingerprint ) )

		{

			continue;

		}



		m_seenAlertFingerprints.insert( fingerprint );



		const auto parts = line.split( QLatin1Char( '|' ) );

		if( parts.size() < 8 )

		{

			vWarning() << "[cimed-version-alert] sentinel ignored malformed alert line" << alertPath;

			continue;

		}



		if( VeyonCore::platform().sessionFunctions().currentSessionHasUser() == false )

		{

			vWarning() << "[cimed-version-alert] sentinel skipped alert: no interactive user session";

			continue;

		}



		vWarning() << "[cimed-version-alert] sentinel dispatching modal for"

				   << parts.at( 1 ) << parts.at( 3 );



		auto& presenter = VeyonCore::builtinFeatures().cimedVersionAlertPresenter();

		presenter.showAlert( m_featureWorkerManager,

							 parts.at( 1 ),

							 parts.at( 2 ),

							 parts.at( 3 ),

							 parts.at( 4 ),

							 parts.at( 5 ) );

	}



	fileState.lastFileSize = fileSize;

}

