	detailsLabel->setWordWrap( true );
	detailsLabel->setAlignment( Qt::AlignTop | Qt::AlignLeft );
	detailsLabel->setSizePolicy( QSizePolicy::Preferred, QSizePolicy::Minimum );
	detailsLabel->setStyleSheet( QStringLiteral(
		"font-size: 13px; font-weight: 600; color: #f8fafc; line-height: 1.45; padding: 12px; "
		"background: rgba(15, 23, 42, 0.55); border-radius: 8px;" ) );
	contentLayout->addWidget( detailsLabel );

	auto* acknowledgeButton = CimedDialogStyle::createPrimaryButton( m_contentPanel, QStringLiteral( "ENTENDI" ) );
	connect( acknowledgeButton, &QPushButton::clicked, this, &QDialog::accept );
	contentLayout->addWidget( acknowledgeButton, 0, Qt::AlignHCenter );

	const auto dialogWidth = CimedDialogStyle::VersionAlertDialogWidth;
	const auto contentWidth = dialogWidth - 96;
	policyLabel->setFixedWidth( contentWidth );
	detailsLabel->setFixedWidth( contentWidth );
	const auto screen = QGuiApplication::primaryScreen();
	const auto maxHeight = screen ? screen->availableGeometry().height() - 48 : 900;
	const auto desiredHeight = versionAlertDialogHeight( *policyLabel,
													   *detailsLabel,
													   contentWidth,
													   CimedDialogStyle::VersionAlertDialogHeight );
	const auto dialogHeight = qMin( desiredHeight, maxHeight );
	const auto needsScroll = desiredHeight > maxHeight;

	if( needsScroll )
	{
		contentLayout->removeWidget( policyLabel );
		contentLayout->removeWidget( detailsLabel );

		auto* scrollContent = new QWidget( m_contentPanel );
		auto* scrollLayout = new QVBoxLayout( scrollContent );
		scrollLayout->setContentsMargins( 0, 0, 0, 0 );
		scrollLayout->setSpacing( 12 );
		scrollLayout->addWidget( policyLabel );
		scrollLayout->addWidget( detailsLabel );

		auto* scrollArea = new QScrollArea( m_contentPanel );
		scrollArea->setWidgetResizable( true );
		scrollArea->setFrameShape( QFrame::NoFrame );
		scrollArea->setHorizontalScrollBarPolicy( Qt::ScrollBarAlwaysOff );
		scrollArea->setStyleSheet( QStringLiteral( "background: transparent;" ) );
		scrollArea->setWidget( scrollContent );
		contentLayout->insertWidget( 0, scrollArea, 1 );
	}

	setFixedSize( dialogWidth, dialogHeight );
	CimedDialogStyle::centerDialogOnScreen( this, dialogWidth, dialogHeight );

	applyPulseTheme( false );
	connect( &m_pulseTimer, &QTimer::timeout, this, [this]() {
		togglePulseTheme();
	} );
	m_pulseTimer.start( 650 );
}

void CimedVersionAlertDialog::applyPulseTheme( bool alertRed )
{
	m_alertRedPhase = alertRed;

	if( alertRed )
	{
		setStyleSheet( alertDialogStyleSheet() );
		if( m_headerWidget != nullptr )
		{
			m_headerWidget->setStyleSheet( alertHeaderStyleSheet() );
		}
		if( m_contentPanel != nullptr )
		{
			m_contentPanel->setStyleSheet( alertContentPanelStyleSheet() );
		}
		return;
	}

	setStyleSheet( CimedDialogStyle::dialogStyleSheet() );
	if( m_headerWidget != nullptr )
	{
		m_headerWidget->setStyleSheet( CimedDialogStyle::headerStyleSheet() );
	}
	if( m_contentPanel != nullptr )
	{
		m_contentPanel->setStyleSheet( CimedDialogStyle::contentPanelStyleSheet() );
	}
}

void CimedVersionAlertDialog::togglePulseTheme()
{
	applyPulseTheme( !m_alertRedPhase );
}
